/**
 * French interpretive text for the 64 hexagrams, keyed by King Wen number.
 * AUTO-GENERATED — translated from the canonical English in @q-ching/core.
 * hexText() falls back to English per-hexagram when an entry is missing.
 */

export interface HexagramText {
  /** French name (replaces the English name in the UI). */
  name: string;
  gloss: string;
  judgment: string;
  image: string;
  lineTexts: [string, string, string, string, string, string];
}

export const HEXAGRAMS_FR: Record<number, HexagramText> = {
  1: {"name":"Le Créateur","gloss":"Force créatrice pure, infatigable et lumineuse","judgment":"Le Créateur opère un succès sublime, que favorise la persévérance. Là réside la puissance première d’où naissent toutes choses et qui les mène à leur achèvement. S’accorder à cette force génératrice et inlassable, c’est trouver la voie ouverte et l’issue assurée.","image":"Le ciel se meut au-dessus du ciel, dans une course sans repos et sans fatigue. Ainsi l’homme noble se rend fort et inépuisable, et ne cesse jamais l’œuvre de son propre renouvellement.","lineTexts":["Le dragon repose, caché sous les eaux ; son heure n’est pas encore venue. Attends sans agir, car le temps de l’essor n’a pas mûri.","Le dragon paraît dans le champ, et le grand homme se laisse voir. Il convient à présent de rechercher le conseil de qui possède une vraie stature.","Tout le jour l’homme noble demeure créateur, et le soir venu reste encore vigilant et sur ses gardes. L’ouvrage est lourd de péril, et pourtant rester sans faute reste possible.","Planant au-dessus de l’abîme, le dragon peut s’élancer vers le haut ou se tenir en bas. À ce tournant, l’un et l’autre choix peuvent être irréprochables s’ils jaillissent de la sincérité.","Le dragon vole dans les cieux ; le grand homme accède à sa pleine puissance. Il est favorable maintenant de rechercher les dignes et de laisser rayonner son influence.","Le dragon orgueilleux monte trop haut et aura sujet de s’en repentir. Ce qui s’élève au-delà de sa mesure n’a plus d’autre chemin que la descente."]},
  2: {"name":"Le Réceptif","gloss":"Abandon dévoué qui soutient toutes choses","judgment":"Le Réceptif apporte un succès sublime par la persévérance d’une jument. Si l’homme noble veut conduire, il s’égare ; en suivant, il trouve son guide. Céder, porter, et achever ce que le créateur commence, telle est la voie qui apporte le bonheur.","image":"La terre, dans toute son ampleur, s’étend ouverte sous le ciel entier et soutient tout ce qui vit. Ainsi l’homme noble élargit sa nature et porte le monde extérieur d’une contenance aussi vaste que le sol même.","lineTexts":["Quand le givre est sous les pas, la glace solide n’est plus loin. Prête attention au premier signe ténu, car les petits commencements mûrissent en grandes conditions.","Droite, carrée et grande par nature, la juste voie n’a besoin d’aucun artifice. À agir sans calcul, rien ne demeure qui ne soit favorisé.","On garde cachées ses lignes ; on peut persévérer en silence. Appelé à servir l’œuvre d’autrui, achève-la sans en revendiquer la gloire.","Un sac noué ne laisse rien entrer ni rien sortir. En un temps de réserve, se taire n’attire ni louange ni blâme.","Un vêtement jaune porté par-dessous apporte le bonheur suprême. La vraie valeur qui demeure au centre et ne fait point d’étalage est la plus bénie de toutes.","Les dragons combattent dans la prairie, et leur sang est noir et jaune. Quand ce qui cède lutte d’égal à égal contre ce qui est fort, tous deux reçoivent la blessure."]},
  3: {"name":"La Difficulté initiale","gloss":"Première germination à travers le chaos et la résistance","judgment":"La Difficulté initiale opère un succès sublime par la persévérance. N’entreprends rien à la légère ; cherche plutôt des aides et mets de l’ordre en toute chose. Comme la jeune pousse force le sol dur, ce qui s’emmêle au départ peut encore croître droit si on le soigne avec justesse.","image":"Les nuées et le tonnerre s’amassent, l’orage n’ayant pas encore crevé en pluie. Ainsi, dans la confusion, l’homme noble donne forme au désordre, démêlant les fils et les remettant chacun à sa place.","lineTexts":["Retenu sur le seuil, il convient de s’arrêter plutôt que de presser le pas. Demeurer constant et rassembler des alliés prépare le terrain de ce qui suit.","Les difficultés s’accumulent ; le cheval et le char font demi-tour. La jeune fille ne s’engage pas maintenant, mais attend dix ans avant que l’union ne mûrisse.","À chasser le cerf sans guide, on ne fait que s’égarer plus avant dans la forêt. Le sage le voit et y renonce, car forcer le passage mènerait à l’humiliation.","Le cheval et le char font encore demi-tour, mais il faut désormais aller chercher l’union. En tendant la main vers un aide digne, la voie devant soi s’ouvre favorablement.","Quand les dons que l’on voudrait offrir sont encore retenus par les circonstances, répands la bénédiction à petite mesure. Vouloir de grandes œuvres maintenant attire le malheur ; la modeste constance l’emporte.","Le cheval et le char se séparent, et coulent des larmes de sang. Au comble de la difficulté, ce qui ne peut être soutenu doit être lâché, et le chagrin enfin se dénoue."]},
  4: {"name":"La Folie de la jeunesse","gloss":"L’inexpérience attendant un patient enseignement","judgment":"La Folie de la jeunesse rencontre le succès. Ce n’est pas moi qui cherche le novice ; le novice me cherche. À la première demande, je réponds ; questionné encore et encore, cela devient importunité, et à l’importun je ne réponds plus. La persévérance est favorable.","image":"Au pied de la montagne jaillit une source qui ne sait pas encore où elle ira courir. Ainsi l’homme noble nourrit son caractère par une conduite résolue et entière, donnant au jeune courant son juste cours.","lineTexts":["Pour dissiper la folie, la discipline sert bien, et les entraves peuvent à juste titre être ôtées une fois. Mais continuer à punir n’apporte que l’humiliation et durcit la faute.","Supporter l’insensé avec bienveillance apporte le bonheur. Prendre le novice sous sa garde, comme une maison recueille les siens, met l’ordre dans le foyer.","Ne prends pas cette jeune fille qui se perd à la vue d’un homme d’airain. Une telle femme ne garde rien d’elle-même ; rien ne se gagne dans cette union.","La folie qui se referme sur elle-même, murée contre tout enseignement, apporte l’humiliation. Coupé des sages, l’esprit s’endurcit dans son erreur.","La folie enfantine qui sait qu’elle ne sait pas apporte le bonheur. L’ouverture de l’élève de bon vouloir attire l’aide dont il a besoin.","En châtiant la folie, il ne sert de rien de commettre un nouveau tort. Il faut détourner le mal, non l’infliger, en se gardant de tout excès dans la correction."]},
  5: {"name":"L’Attente","gloss":"Confiance patiente devant le seuil","judgment":"L’Attente, si tu es sincère, porte la lumière et le succès ; la persévérance apporte le bonheur, et il est favorable de traverser la grande eau. Quand le danger se tient devant soi, la force ne se précipite pas mais attend son heure avec une certitude intérieure. Nourri par la confiance, celui qui attend dans le juste esprit n’attendra pas en vain.","image":"Les nuées montent dans les cieux, retenant la pluie qui n’est pas encore tombée. Ainsi l’homme noble mange et boit, se réjouit et garde le cœur léger, laissant l’heure fixée venir en son propre temps.","lineTexts":["Attendre dans la prairie ouverte, loin du danger, c’est bien demeurer dans ce qui dure. À persévérer ici, on reste sans faute.","Attendre sur le sable : le bord de l’eau se rapproche et les menus propos commencent. Bien qu’il y ait quelque friction légère, à la fin vient le bonheur.","Attendre dans la boue, c’est s’être trop approché et inviter le trouble à venir. La prudence et la vigilance tiennent désormais la perte à distance.","Attendre dans le sang, tombé jusque dans la fosse même du danger, le seul conseil est de rester immobile. Souple et serein, on se laisse porter hors des profondeurs.","Attendre devant la viande et le vin, répit au milieu de l’épreuve. La persévérance apporte le bonheur, et la force se rétablit pour ce qui reste à venir.","Tombé dans la fosse, trois hôtes non conviés arrivent sans qu’on les appelle. Accueille-les avec respect, et à la fin le bonheur accompagne ce qui semblait un malheur."]},
  6: {"name":"Le Conflit","gloss":"La discorde, mieux dénouée avant son terme","judgment":"Dans le conflit il y a une sincérité qui se trouve pourtant entravée ; un arrêt prudent à mi-chemin apporte le bonheur, mais le mener jusqu’à l’amère extrémité apporte le malheur. Il est favorable de voir le grand homme ; il n’est pas favorable de traverser la grande eau. Là où la force rencontre le danger, le sage cherche un juste règlement plutôt qu’une victoire définitive.","image":"Le ciel monte et l’eau descend, les deux se mouvant en sens contraires et ne se rencontrant jamais. Ainsi l’homme noble, en tout ce qu’il entreprend, considère le commencement avec soin, afin que la discorde soit écartée avant même de naître.","lineTexts":["Si l’on ne prolonge pas la querelle, il y a un peu de médisance, mais à la fin le bonheur. Laisse l’affaire reposer tôt, et le différend se dissout.","Incapable de l’emporter dans le conflit, on rebrousse chemin et s’esquive. Une maison de trois cents âmes ne subit aucun dommage quand son chef cède à temps.","Nourri par la vertu ancienne, on persévère face au danger et l’on finit dans le bonheur. Si l’on sert aux affaires d’un prince, ne revendique rien comme étant à soi.","Incapable de gagner la contestation, on revient accepter son sort, on change de cœur et l’on trouve la paix dans la fermeté. Céder à ce qui est juste apporte le bonheur.","Porter le conflit devant un juge droit et impartial apporte le bonheur suprême. Là où le droit est pesé par une véritable autorité, l’affaire se règle avec justesse.","Même si l’on reçoit une ceinture d’honneur, avant la fin de la matinée elle est arrachée trois fois. La victoire gagnée par la discorde ne peut être tenue avec sûreté."]},
  7: {"name":"L’Armée","gloss":"Force disciplinée sous un commandement de confiance","judgment":"L’Armée exige la persévérance et un chef d’une force éprouvée ; alors il y a bonheur et nul blâme. Une multitude doit être mue par la discipline et par une cause juste, rassemblée autour de celui en qui tous peuvent placer leur confiance. La force bien ordonnée et bien conduite apporte l’ordre ; la force privée de cela apporte la ruine.","image":"L’eau est contenue dans la terre, l’abîme rassemblé sous le champ. Ainsi l’homme noble, par sa générosité envers le peuple, rassemble et soutient les multitudes autour de lui.","lineTexts":["Une armée doit se mettre en marche dans le bon ordre dès le début. Sans discipline au départ, même une cause digne aboutit au malheur.","Posté au milieu de la troupe, le chef tient le centre et obtient le bonheur sans blâme. La triple faveur du prince confirme la confiance placée en lui.","Si l’armée transporte des cadavres dans son char, le malheur s’ensuit. Quand le commandement est divisé ou indigne, la campagne s’achève en ruine.","L’armée bat en retraite et établit son camp ; il n’y a pas de blâme à se retirer. Savoir quand ne pas avancer est en soi la marque d’un commandement sûr.","Il y a du gibier dans le champ, et il est juste de le prendre ; cela n’apporte pas de blâme. Que l’aîné conduise la troupe, car si les jeunes et les novices commandent, les chars ramènent les morts.","Le grand prince émet ses ordres, fonde des États et accorde des fiefs aux dignes. Mais les hommes inférieurs ne doivent pas être employés, de peur que l’ordre conquis ne se défasse."]},
  8: {"name":"La Solidarité","gloss":"Union fondée sur une allégeance sincère","judgment":"La Solidarité apporte le bonheur. Interroge l’oracle une fois encore, pour savoir si tu possèdes constance, grandeur et endurance ; s’il en est ainsi, il n’y a pas de blâme. Les hésitants qui tardent arrivent trop tard et rencontrent le malheur ; que les indécis se rassemblent maintenant, tandis que le moment de l’union reste ouvert.","image":"L’eau coule sur la terre, emplissant chaque creux et se liant au sol. Ainsi les anciens rois fondèrent les nombreux États et attirèrent les seigneurs féodaux en un lien étroit et confiant.","lineTexts":["Tiens-toi solidaire avec sincérité, et il n’y a pas de blâme. Que la vérité t’emplisse comme un vase jusqu’au bord, et le bonheur vient de quartiers inattendus.","La solidarité qui s’élève du dedans apporte le bonheur par la persévérance. L’union qui jaillit de sa propre nature véritable ne se perd pas elle-même.","Se tenir solidaire des mauvaises gens ne mène à rien de bon. Lié à des indignes, on dépense sa loyauté sur une terre stérile.","Se tenir solidaire de ceux qui sont au-dehors de soi, ouvertement et au grand jour, apporte le bonheur. Suivre les dignes sans rien dissimuler est favorable.","Solidarité manifeste, comme le roi qui rabat le gibier sur trois côtés seulement et laisse libre le devant. Le peuple n’a besoin d’aucun avertissement et demeure en paix ; c’est le bonheur.","La solidarité qui manque de tête et de centre directeur aboutit au malheur. Là où nul commencement n’est justement fait, il ne peut y avoir de bonne fin."]},
  9: {"name":"Le Pouvoir d’apprivoisement du petit","gloss":"Le petit retient le fort ; des nuées sans pluie","judgment":"Le succès vient, mais seulement dans les petites choses. Des nuées épaisses s’amassent au bord occidental du ciel, et pourtant nulle pluie n’est encore tombée. Une seule force douce retient le fort pour un temps ; le grand courant est contenu mais non détourné, et il faut attendre que l’humidité parvienne à maturité.","image":"Le vent souffle sur la face du Ciel et meut le fort sans l’arrêter. Ainsi l’homme noble affine la grâce de la forme extérieure et l’éclat du caractère, parfaisant les petites vertus tant que l’œuvre plus grande ne peut encore s’accomplir.","lineTexts":["Il revient sur sa propre route. Comment y aurait-il là un blâme ? La bonne fortune réside dans le retour à la voie qui est justement la tienne.","Ramené sur la route par l’exemple qui le précède, il revient de plein gré et ne se laisse point égarer. Suivre ce qui convient apporte la bonne fortune.","Les rayons jaillissent des roues du char, et l’époux et l’épouse détournent l’un de l’autre leur regard. La marche en avant ne peut tenir ; la retenue l’a vaincue de l’intérieur.","Là où il y a sincérité, le sang s’en va et l’effroi se dissipe. Maintenu en un lieu de danger, il a la confiance de ceux d’en haut, et nulle faute ne demeure.","Il est sincère et lie les autres à lui ; par la vérité il attire son voisin tout près, et partage son abondance plutôt que de l’amasser.","La pluie vient enfin, et le lieu de repos est atteint ; le petit pouvoir a produit tout son effet. Pourtant la femme qui veut aller plus loin courtise le danger, et l’homme noble qui agit maintenant attire le malheur."]},
  10: {"name":"La Marche","gloss":"Marcher sur la queue du tigre avec précaution","judgment":"On marche sur la queue du tigre, et pourtant il ne mord pas. Affrontant une force écrasante avec une courtoisie enjouée, le faible trouve le passage là où la force échouerait. Une conduite correcte et de belle humeur mène sain et sauf à travers le danger.","image":"Le Ciel se tient en haut, le Lac brille en bas, chacun gardant sa place propre. Ainsi l’homme noble discerne le haut du bas et affermit la volonté du peuple, donnant à chaque rang la tenue qui lui convient.","lineTexts":["Il suit son chemin tout simple et avance sans entrave. Sans blâme, car celui qui se contente de la simplicité peut avancer sans rencontrer de reproche.","Il marche sur une route plane et unie ; le solitaire qui s’y tient demeure ferme et trouve la bonne fortune. Une constance tranquille le préserve.","Un borgne croit voir clair, un boiteux croit pouvoir marcher à grands pas ; marchant sur la queue du tigre, il est mordu. Malheur. Les audacieux qui passent leur mesure courent à la ruine.","Il marche sur la queue du tigre, mais avec circonspection et un effroi intérieur. À la fin, bonne fortune, car la prudence écarte le danger.","Il marche d’un pas résolu, d’une conduite pleine et décidée. Même dans ce qui est juste, garde conscience du péril ; la fermeté seule ne doit pas devenir témérité.","Considère en arrière le chemin parcouru et pèse les signes qu’il porte. Quand le cours entier s’arrondit jusqu’à son achèvement, la suprême bonne fortune advient."]},
  11: {"name":"La Paix","gloss":"Le Ciel et la Terre en union ; la paix qui fleurit","judgment":"Le petit s’en va et le grand approche ; bonne fortune et succès se déploient. Le Ciel et la Terre se joignent en une union vivante, et tous les êtres prospèrent dans l’harmonie de leur mêlée. C’est la saison de la floraison, où le haut et le bas n’ont qu’un seul accord.","image":"La Terre repose en haut, le Ciel se meut en bas, et leurs souffles s’écoulent ensemble en union. Ainsi le souverain façonne et achève le cours du Ciel et de la Terre, ordonnant leurs dons de manière à soutenir le peuple.","lineTexts":["Quand on arrache l’herbe en ruban, ses racines viennent enlacées les unes aux autres ; partir maintenant apporte la bonne fortune, car les dignes s’élèvent d’un seul mouvement et entraînent leurs semblables.","Il supporte ce qui est inculte, franchit hardiment le fleuve, ne néglige rien de lointain et ne forme aucune faction. Ainsi il marche sur la voie du milieu et l’honore.","Il n’est point de plaine qui ne devienne pente, point de départ sans retour. Demeure ferme dans l’épreuve et ne ressens nul chagrin ; fie-toi à la plénitude donnée, et jouis de sa bénédiction.","Il descend en voltigeant, sans se vanter de sa richesse, se rapprochant de ses voisins en toute bonne foi. Le haut s’abaisse vers le bas d’un cœur sincère et ouvert.","Le roi Yi donne sa fille en mariage, et de là viennent la bénédiction et la suprême bonne fortune. Le noble cède à l’humble, et l’abondance s’ensuit.","Le mur de la cité s’écroule dans les douves. N’use d’aucune armée maintenant ; que le décret se proclame au-dedans de tes propres frontières. Si juste soit-il, cela donne lieu au regret, car la paix a atteint son tournant."]},
  12: {"name":"La Stagnation","gloss":"Le Ciel et la Terre séparés ; le temps de la stagnation","judgment":"La stagnation est l’œuvre des êtres indignes, et elle ne favorise pas la constance de l’homme noble. Le grand s’en va et le petit approche ; le Ciel et la Terre se séparent, et leurs souffles ne se mêlent plus. C’est un temps pour se retenir et ne point avancer.","image":"Le Ciel s’élève et se retire en haut, la Terre s’abaisse et se retire en bas, et les deux ne se rencontrent plus. Ainsi l’homme noble retire en lui l’éclat de sa vertu pour échapper à l’épreuve, et ne se laisse tenter ni par le rang ni par la récompense.","lineTexts":["Quand on arrache l’herbe en ruban, ses racines viennent enlacées les unes aux autres ; demeurer ferme apporte la bonne fortune et le succès. Retire-toi avec les tiens et garde la foi.","Ils endurent et supportent ; pour les petites gens cela apporte la bonne fortune, tandis que le grand homme accepte la stagnation et rencontre ainsi le succès. Ne te laisse point emporter par le flot commun.","Il porte sa honte en silence, dissimulant le déshonneur qu’il ressent. Les indignes, élevés au-delà de leur mesure, sont au-dedans troublés par ce qu’ils ne peuvent soutenir.","Il agit sur l’ordre du Très-Haut, et nul blâme ne s’y attache ; ceux qui partagent son dessein ont part à la bénédiction. Le revirement commence à venir.","La stagnation tire vers sa fin, et le grand homme trouve la bonne fortune. Pourtant il doit dire : « Cela pourrait manquer, cela pourrait manquer », et lier sa sécurité à un bouquet de pousses de mûrier.","La stagnation est renversée ; il y eut d’abord stagnation, puis vient la joie. Ce qui stagnait ne dure point, car rien ne demeure à jamais immobile."]},
  13: {"name":"La Communauté avec les hommes","gloss":"Communauté ouverte ; union d’un dessein clair et commun","judgment":"La communauté rassemblée au grand jour, dans la plaine, apporte le succès. Il est favorable de traverser la grande eau, et de tenir à la constance de l’homme noble. Quand l’union repose sur ce qui est clair et commun à tous, de grandes entreprises peuvent être menées à bon port.","image":"Le Feu monte vers le Ciel, sa lumière atteignant ce qui est haut au-dessus. Ainsi l’homme noble trie les semblables selon leurs espèces et discerne la nature des choses, sachant où la vraie communauté peut reposer.","lineTexts":["Communauté au seuil de la porte, dans la simple clarté du seuil ouvert. Nul blâme, car une union commencée sans dissimulation ni partialité n’offense personne.","Communauté au sein du clan seulement. Cela apporte l’humiliation, car se lier à un cercle étroit, c’est rester en deçà de la plaine ouverte.","Il cache des armes dans le fourré et gravit la haute colline pour guetter ; trois ans durant il ne peut se lever pour agir. La méfiance le tient en armes mais le retient du combat.","Il monte sur le rempart, et pourtant ne presse pas l’attaque. Bonne fortune, car il se détourne de la querelle et cède à ce qui est juste.","Les compagnons d’abord pleurent et se lamentent, et ensuite ils rient ; car après de grandes luttes ils se rejoignent enfin. Ce qui est justement lié ne peut être tenu séparé.","Communauté dans la prairie, au-delà des murs. Nul regret, bien que l’union soit encore incomplète, car le but est sain là même où le plein objet n’est pas encore atteint."]},
  14: {"name":"Le Grand Avoir","gloss":"Le grand avoir tenu dans une lumière claire et humble","judgment":"Le grand avoir apporte le succès suprême. Un seul esprit cédant occupe la place centrale, et les forts se rassemblent de plein gré pour le servir. Quand l’abondance est gouvernée avec clarté et humilité, le temps lui-même confère la bonne fortune.","image":"Le Feu flamboie haut au-dessus du Ciel, jetant sa lumière au loin sur toutes choses. Ainsi l’homme noble réprime ce qui est bas et mauvais, et soutient ce qui est bon, obéissant à la volonté bienveillante du Ciel et ordonnant ainsi le destin lumineux qui lui est confié.","lineTexts":["Nul commerce encore avec ce qui est nuisible, et donc nul blâme ; si l’on demeure attentif à l’épreuve, l’abondance reste sans faute. Le commencement est encore intact et pur.","Un grand char pour la charge, et un but vers lequel conduire. Partir maintenant est sans blâme, car une force ample est accordée à un dessein digne.","Un prince offre sa richesse en tribut au Fils du Ciel. L’homme petit et avide ne saurait le faire, car il ne peut donner ce que l’abondance a mis entre ses mains.","Il fait une distinction entre lui-même et l’étalage de son voisin, et se tient dans sa mesure. Nul blâme, car celui qui n’affiche pas sa richesse échappe à l’envie des puissants.","Sa sincérité gagne les autres et rencontre en retour une sincérité semblable ; la dignité tempère son accès, et la bonne fortune s’ensuit. La vérité portée avec une tranquille majesté attire tous les cœurs.","Il est béni par le Ciel lui-même. Bonne fortune ; rien qui ne favorise, car celui qui, dans le grand avoir, demeure modeste et pieux est soutenu d’en haut."]},
  15: {"name":"L’Humilité","gloss":"La grandeur tenue basse ; la montagne au sein de la terre","judgment":"L’humilité crée le succès ; l’homme noble mène son entreprise jusqu’au bout. Le Ciel envoie sa lumière vers le bas et resplendit, et la Terre dans sa bassesse s’élève à sa rencontre. Ce qui est haut, elle l’abaisse ; ce qui est bas, elle l’élève, et les humbles sont menés à leur accomplissement.","image":"Au-dedans de la Terre demeure la Montagne, sa grande masse cachée sous le sol uni. Ainsi l’homme noble retranche de là où il y a trop et ajoute à là où il y a trop peu, pesant toutes choses et les dispensant d’une main égale.","lineTexts":["Humble et de nouveau humble est l’homme noble ; avec une telle humilité il peut traverser la grande eau, et la bonne fortune s’ensuit. La basse contenance du digne le porte à travers le danger.","Une humilité qui trouve sa voix et que tous voient. Persévérer apporte la bonne fortune, car l’humilité montée jusqu’à l’expression sonne juste au cœur.","L’homme noble qui peine et reste pourtant humble mène son œuvre à son achèvement. Bonne fortune, car le mérite joint à l’humilité gagne la durable allégeance du peuple.","Rien qui ne favorise le déploiement de l’humilité dans l’action. Il se meut dans ses bornes et ne transgresse point la règle, ne reculant ni n’outrepassant.","Sans se vanter de sa richesse, il attire ses voisins ; il est favorable d’user de force contre l’intraitable, et rien ne manque de favoriser. Même des mesures fermes, prises dans l’humilité, sont sans reproche.","Une humilité qui trouve sa voix ; il est favorable de mettre les armées en marche et de discipliner son propre domaine. Il peut corriger ce qui est à sa portée, car son humilité lui a gagné le droit d’agir."]},
  16: {"name":"L’Enthousiasme","gloss":"Le tonnerre réveillant la terre ; rassemblés, la joie inspirée","judgment":"L’enthousiasme favorise la nomination des aides et la mise en mouvement des armées. Quand le mouvement suit la ligne de moindre résistance, toutes choses tombent à leur place consentante, comme le Ciel et la Terre gardent leurs saisons sans effort. Ainsi le peuple se rassemble avec joie derrière un chef qui l’éveille.","image":"Le tonnerre jaillit de la Terre, résonnant en une joyeuse libération. Ainsi les rois anciens firent de la musique pour honorer le mérite, l’offrant en splendeur au Très-Haut et conviant leurs ancêtres à y prendre part.","lineTexts":["L’enthousiasme qui se prodigue en ostentation apporte le malheur. Se vanter de ses relations et dilapider la joie en vanité épuise la source.","Ferme comme le roc, et non pour un seul jour ; persévérer apporte la bonne fortune. Il ne flatte point ceux d’en haut ni ne méprise ceux d’en bas, mais lit les germes cachés des choses.","L’enthousiasme qui regarde en haut et attend apporte le remords ; l’hésitation, elle aussi, apporte le remords. Celui qui contemple les puissants au lieu d’agir perd le moment à force de tarder.","La source d’où l’enthousiasme s’écoule ; de grandes choses peuvent s’accomplir. Ne doute de rien, car les amis se rassemblent autour de lui comme l’agrafe rassemble les mèches des cheveux.","Constamment malade, et pourtant il ne meurt pas. Une pression incessante d’en haut le tient à l’étroit, et pourtant la force centrale en lui n’est jamais tout à fait éteinte.","Un enthousiasme devenu aveugle et perdu en lui-même ; pourtant si, quand tout est consommé, il y a un changement de cœur, alors nul blâme. Même l’aveuglement peut être racheté quand il revient à temps."]},
  17: {"name":"La Suite","gloss":"S’adapter, et l’on sera suivi","judgment":"La Suite ouvre la voie à une sublime réussite, et nul blâme ne s’attache à celui qui demeure ferme et droit. Pour être suivi, il faut d’abord savoir suivre ; pour conduire les autres, il faut d’abord apprendre à servir l’instant. Tiens-toi à ce qui est juste, et la fidélité d’autrui se rassemblera d’elle-même autour de toi.","image":"Le tonnerre repose endormi au sein du Lac, et l’orage qui jadis grondait s’apaise désormais en repos. Ainsi l’homme noble, quand le jour décline, se retire à l’intérieur pour se renouveler et trouver le calme, suivant le rythme de l’heure plutôt que de lutter contre lui.","lineTexts":["La mesure intérieure se déplace ; ce qui tenait ferme cède maintenant à un ordre nouveau. Franchis le seuil de ta propre porte pour te mêler librement aux autres, et tes entreprises porteront leurs fruits.","Si tu t’attaches au petit enfant, tu laisses échapper le compagnon vigoureux. On ne peut tenir les deux à la fois : choisis ce qui a du prix et lâche le reste.","En t’attachant à l’homme fort, tu renonces au petit enfant. Tu obtiens ce que tu cherches vraiment, mais il te faut demeurer ferme dans ton dessein et ne pas te laisser dévier de ta route.","Suivre attire des partisans, et l’influence s’accroît. Ici, même un gain légitime éveille le soupçon ; tiens-toi à la sincérité et à la clarté du dessein, et nulle faute ne s’attachera à toi.","Sincère envers ce qui est bon et beau, tu suis la voie supérieure sans jamais vaciller. Une telle constance apporte une fortune qui n’a nul besoin d’être défendue.","Le lien est si solide qu’il semble noué et tenu ferme. Le roi présente son offrande sur la montagne de l’occident ; un dévouement si entier est honoré à sa source même."]},
  18: {"name":"Le Travail sur ce qui est corrompu","gloss":"Réparer la décadence héritée","judgment":"Le travail sur ce qui est corrompu ouvre la voie à une suprême réussite, car la décadence, affrontée de face, devient le commencement du renouveau. Il convient de traverser la grande eau et d’entreprendre la tâche. Considère trois jours avant le point de retournement et trois jours après, car ce qui fut laissé à l’abandon n’a pas pourri en un jour, et sa réfection doit être mesurée.","image":"Sous la Montagne immobile, le Vent souffle bas et tournoyant, dispersant les choses du monde dans le désordre. Ainsi l’homme noble éveille le peuple et le met à l’ouvrage, et par un labeur honnête nourrit à nouveau son caractère.","lineTexts":["Réparant ce que le père a gâté, le fils rachète le nom de l’aïeul ; là où il est un tel héritier, nul blâme ne subsiste. Le danger persiste, mais la fin est heureuse.","Réparant ce que la mère a gâté, avance avec douceur et ne force pas la correction. Une main trop rigide ne saurait ici redresser quoi que ce soit.","Réparant ce que le père a gâté, il y a un léger regret d’avoir agi avec trop de vigueur, mais nulle faute grave ne s’ensuit.","Tolérer et excuser ce que le père a gâté, c’est laisser la pourriture s’approfondir. Persiste sur cette voie, et tu ne rencontreras que l’humiliation.","Réparant ce que le père a gâté, tu mérites la louange et tu es accueilli avec honneur. L’ouvrage, repris comme il faut, attire la reconnaissance.","Il ne sert ni roi ni prince, mais place ses propres affaires, plus hautes, au-dessus des leurs. Se retirant de l’ouvrage commun, il veille à un dessein plus élevé, digne d’estime."]},
  19: {"name":"L’Approche","gloss":"Le fort se rapproche avec attention","judgment":"L’Approche ouvre la voie à une sublime réussite, et il est favorable de demeurer ferme et droit. Pourtant un avertissement se mêle à la promesse : quand viendra le huitième mois, le malheur surviendra. Ce qui s’élève à présent doit se souvenir que sa saison n’est pas sans fin.","image":"La Terre repose au-dessus du Lac, la hauteur se penchant tout près des profondeurs qu’elle domine. Ainsi l’homme noble est inépuisable dans la volonté d’enseigner et infatigable dans la tolérance, abritant et soutenant le peuple sans limite.","lineTexts":["Approchant de concert, dans un dessein partagé, la voie est ouverte. Tiens-toi fermement à ce qui est juste, et la fortune s’ensuit.","Approchant de concert, dans un dessein partagé, vient la fortune, et tout tourne au mieux. Avance sans nulle inquiétude.","Une approche complaisante, qui flatte et présume, ne sert à rien de bon. Pourtant, si l’on s’afflige de la faute et qu’on l’amende, le blâme ne durera pas.","S’approchant avec un dévouement plein et sans défaut, l’approche atteint sa juste place. Il n’y a nulle erreur à se donner tout entier.","Une approche pleine de sagesse, digne d’un grand souverain, gouverne par autrui sans rien saisir pour soi. Telle est la voie de la fortune.","Une approche d’une grandeur généreuse, au cœur large et sans hâte, apporte la fortune et demeure libre de tout blâme."]},
  20: {"name":"La Contemplation","gloss":"Contempler et être contemplé","judgment":"La Contemplation est comme l’ablution qui précède l’offrande, lorsque les mains sont lavées mais le sacrifice non encore accompli. Dans cette pause, la sincérité se rassemble et resplendit, et ceux qui la regardent sont émus de respect. Sois l’exemple que les autres peuvent contempler, et ta seule tenue deviendra un enseignement.","image":"Le Vent passe sur la face de la Terre, parcourant toutes choses et touchant chacune à son tour. Ainsi les rois d’autrefois parcouraient les quatre régions, observaient le peuple et dispensaient leur enseignement selon ce qu’ils voyaient.","lineTexts":["Une contemplation puérile et superficielle ne voit que la surface. Pour l’homme du commun, il n’en vient nul mal, mais pour celui d’un rang plus élevé, elle apporte le regret.","Une contemplation furtive par l’entrebâillement de la porte ne voit que peu de l’ensemble. Une vue si étroite convient à qui demeure au foyer, mais pour un homme d’envergure elle est cause de honte.","En contemplant le cours de sa propre vie, en observant s’il faut avancer ou se retirer, on apprend à lire l’instant et à choisir sans erreur.","En contemplant la lumière et l’abondance du royaume, on devient digne d’être l’hôte du roi, servant là où se rencontrent l’influence et l’honneur.","En contemplant sa propre vie et sa conduite, l’homme noble se penche au-dedans sur l’effet qu’il projette sur autrui. Jugé à ce miroir, il est sans blâme.","En contemplant la vie de tout ce qui est sous le ciel, en observant l’ensemble plutôt que le seul moi, l’homme noble se tient libre de toute faute."]},
  21: {"name":"Mordre au travers","gloss":"Briser l’obstacle","judgment":"Mordre au travers ouvre la voie à la réussite, car l’obstacle logé entre les mâchoires doit être brisé avant que l’union puisse être rétablie. Il est favorable d’administrer la justice et de laisser la loi suivre son cours. Là où une chose dure barre le chemin, une force décidée, appliquée avec équité, est le seul remède.","image":"Le Tonnerre et l’Éclair se rencontrent, l’un frappant et l’autre illuminant, et ensemble ils rendent la loi manifeste à tous. Ainsi les rois d’autrefois affermissaient leurs peines et clarifiaient leurs lois, joignant la vue claire à l’action vigoureuse.","lineTexts":["Ses pieds sont pris dans les ceps, en sorte que les orteils sont cachés, et une petite faute est arrêtée avant de grandir. Il n’y a nul blâme à être corrigé de bonne heure.","En mordant la chair tendre, on s’enfonce si profond que le nez disparaît. La faute punie est manifeste et le reproche est vif, mais nul blâme ne s’y attache.","En mordant une viande séchée et gâtée, on rencontre quelque chose d’infect et l’on en est empoisonné. Il y a une légère humiliation, mais nulle véritable faute, car la tâche elle-même était ardue.","En mordant un cartilage séché et enroulé autour de l’os, on y trouve des pointes de flèche en métal. Il est favorable d’être attentif à l’épreuve et de demeurer droit ; persévère, et la fortune vient.","En mordant une viande maigre et séchée, on y trouve de l’or jaune. Tiens-toi à ton dessein avec la conscience du danger, et nul blâme ne s’ensuivra.","Son cou est serré dans la cangue, en sorte que les oreilles sont cachées, car il n’a pas voulu entendre la correction. Cela apporte le malheur à qui reste sourd à l’avertissement."]},
  22: {"name":"La Grâce","gloss":"La beauté qui pare le vrai","judgment":"La Grâce ouvre la voie à la réussite, mais dans les petites choses il est favorable d’entreprendre quelque chose. La parure prête beauté et aisance aux affaires menues, mais l’ornement seul ne saurait décider de ce qui est grand. Que la forme serve la substance, et la forme sera plaisante.","image":"Le Feu rougeoie au pied de la Montagne, projetant sa lumière vers le haut et prêtant aux cimes une splendeur passagère. Ainsi l’homme noble apporte clarté et ordre aux affaires du jour, mais ne présume pas de trancher les graves questions de justice sur la seule apparence.","lineTexts":["Il prête grâce à ses orteils, laisse le char derrière lui et s’en va à pied. Refusant une aisance indigne, il marche sur sa propre route honnête.","Il prête grâce à la barbe de son menton. La parure doit suivre ce qu’elle pare et ne s’élever qu’avec celui qu’elle sert.","Paré et oint, luisant comme s’il avait reçu l’onction, tout paraît beau et fluide. Persévérer fermement en cela apporte une fortune durable.","Paré ou simple, le cheval blanc vient comme porté par des ailes. Ce n’est point un brigand, mais un prétendant ; la simple vérité, une fois aperçue, met fin à tout soupçon.","La grâce sur les collines et dans le jardin, où le rouleau de soie offert est maigre et menu. Il y a humiliation dans la petitesse du présent, mais à la fin la fortune vient.","Une grâce d’un blanc dépouillé, l’ornement ramené à la simplicité, ne laisse nul blâme. Quand la parure revient à la pureté, la forme a atteint sa vérité."]},
  23: {"name":"L’Éclatement","gloss":"La décomposition gagne d’en bas","judgment":"L’Éclatement montre les forces obscures qui s’élèvent tandis que la lumière s’use depuis le bas. En un tel temps, il n’est pas favorable d’aller où que ce soit ni de rien entreprendre. Le sage cède à la saison, demeurant immobile jusqu’à ce que l’usure ait achevé son cours.","image":"La Montagne repose sur la Terre, et ce qui devrait se dresser haut est miné par en dessous. Ainsi ceux d’en haut ne peuvent assurer leur place qu’en se montrant généreux envers ceux d’en bas, fortifiant le fondement qui les porte.","lineTexts":["Le pied du lit est fendu, et ce qui est ferme est détruit à la base même. Le malheur commence là où on peut le moins le voir.","Le cadre du lit est fendu, et le soutien qui devrait tenir ferme cède. Demeurer seul à présent, sans alliés, apporte le malheur.","Il se sépare de ceux qui l’entourent, rompant avec la décadence qui l’environne. En choisissant le juste à contre-courant, il n’y a nul blâme.","Le lit est fendu jusqu’à la peau, et le danger a atteint le corps même. Le malheur presse de tout près, et il n’est plus aucun abri.","Un cordon de poissons, et la faveur des dames du palais suit en bon ordre. Conduits avec grâce vers la lumière, tout tourne à l’avantage et rien n’est sans bienfait.","Un grand fruit demeure non mangé, gardant la semence de tout ce qui est à venir. L’homme noble est porté comme sur un char, tandis que la maison du petit est mise en pièces."]},
  24: {"name":"Le Retour","gloss":"Le point de retournement de la lumière","judgment":"Le Retour ouvre la voie à la réussite, car la lumière, une fois épuisée, revient sans effort ni dommage. Des amis arrivent et il n’y a nulle faute ; la voie tourne et revient encore, achevant son cours en sept jours. Il est favorable d’avoir où aller, car le mouvement de la vie se renouvelle de lui-même.","image":"Le tonnerre s’éveille à nouveau au sein des profondeurs de la Terre, première pulsation de la vie qui revient au cœur de l’hiver. Ainsi les rois d’autrefois fermaient les passes au solstice, arrêtant marchands et voyageurs, afin que le tendre commencement pût rassembler ses forces sans être troublé.","lineTexts":["Revenant de peu de distance, on rebrousse chemin avant de s’égarer trop loin. Il n’est nul besoin de remords, et l’issue est d’une sublime fortune.","Un retour paisible et de bon gré, content de revenir en bonne compagnie, apporte la fortune. Suivre ce qui est bon n’est nulle faiblesse.","Revenir encore et encore, hésitant et répété, trahit un cœur inquiet. Il y a danger dans une telle indécision, mais nul blâme durable.","Marchant au milieu des autres, on revient seul vers la juste voie. Bien que mis à l’écart de la foule, le retour solitaire est vrai.","Un retour au cœur noble, pesé dans un sincère examen de soi, ne laisse nul motif de regret. Sonder sa propre conduite, c’est rentrer chez soi comme il faut.","Un retour égaré, manquant l’instant de rebrousser chemin, apporte le malheur et un dommage durable. Les armées mises en marche à présent finiront dans une grande défaite, et le souverain en pâtira des années durant."]},
  25: {"name":"L’Innocence","gloss":"Agir depuis le cœur sans calcul","judgment":"Quand le cœur est vrai et libre de tout calcul, la réussite est suprême, et la constance porte sa récompense. Mais si la volonté se détourne de ce qui est juste, l’infortune survient, et l’on ne gagne rien à se mettre en route. Agis depuis ta nature, non depuis le calcul, et le ciel lui-même se meut avec toi.","image":"Sous le ciel, le tonnerre roule, et toutes choses s’éveillent à leur être innocent. Ainsi l’homme noble nourrit chaque créature en sa juste saison, riche de vertu et fidèle à l’ordre de la nature, ne demandant à la vie que ce que la vie offre librement.","lineTexts":["L’innocence, en son premier mouvement, te porte en avant ; avance, car le cœur encore sans calcul trouvera son chemin.","Ne compte pas la moisson pendant que tu laboures, ni n’arpente le champ pendant que tu le défriches ; travaille sans songer à la récompense, et il est bon d’aller de l’avant.","Une infortune imméritée peut frapper : le bœuf attaché au bord du chemin est emmené par un passant, et l’homme du village porte la perte sans avoir failli.","Tiens ferme à ce qui te revient de droit et n’aie rien à demander à personne ; en demeurant inébranlable, tu ne saurais vraiment errer.","Un mal qui survient sans que tu y sois pour rien n’a pas besoin de remède ; laisse-le passer sans le traiter, et il guérira de lui-même.","Quand l’innocence voudrait forcer le passage, agir fait du tort ; ici, même l’irréprochable doit se tenir en repos, car le temps lui-même interdit le pas."]},
  26: {"name":"Le Pouvoir d’apprivoisement du grand","gloss":"La force retenue et amassée","judgment":"Le grand accumulement : il est favorable d’être ferme et persévérant. Manger son pain hors de chez soi porte fortune, car la force amassée est destinée au vaste monde. Il est avantageux de traverser la grande eau.","image":"Le ciel demeure au sein de la montagne, vaste puissance retenue dans l’immobilité et tenue en réserve. Ainsi l’homme noble étudie les paroles et les actes des anciens, les amassant au-dedans, jusqu’à ce que ses richesses intérieures soient assez grandes pour agir.","lineTexts":["Le danger attend en avant, et la voie sage est de s’arrêter ; ne te hâte pas, mais accepte la retenue qui t’est imposée.","L’essieu se détache de lui-même du char ; la force puissante fait halte, et il n’y a nul blâme à demeurer immobile.","Maintenant les chevaux galopent côte à côte et la voie s’ouvre ; mais reste vigilant et exerce chaque jour la garde, tenant ferme, et il est bon d’avoir où aller.","Une planche de garde posée sur les cornes du jeune taureau, avant que les cornes n’aient durci, écarte le mal à sa source ; grande est la fortune.","Les défenses d’un sanglier châtré : la puissance dangereuse est bridée à la racine et s’apprivoise ; voici la fortune.","On atteint la voie ouverte du ciel, où la vertu amassée trouve enfin sa délivrance ; la réussite coule sans entrave."]},
  27: {"name":"Les Commissures de la bouche","gloss":"Ce que nous absorbons nous façonne","judgment":"La nourriture : demeurer inébranlable porte fortune. Observe ce qu’un homme donne pour être nourri, et comment il cherche à remplir sa propre bouche, et tu connaîtras sa valeur. Sois attentif à ce que tu absorbes, du corps comme de l’esprit.","image":"Au pied de la montagne, le tonnerre s’éveille, image de la nourriture donnée et reçue. Ainsi l’homme noble veille sur les paroles qui sortent de sa bouche et sur la mesure de ce qui y entre, gardant la source des mots et la source de la vie.","lineTexts":["Tu délaisses ta propre force nourricière pour contempler avec envie les joues pleines d’autrui ; cela porte l’infortune.","Chercher la nourriture auprès de ceux d’en bas, ou se tourner vers les hauteurs pour ce qui devrait venir de tes pairs, s’écarte de la juste voie ; partir ainsi porte l’infortune.","La nourriture recherchée contre l’ordre naturel ne donne rien de bon, quoique tu t’y tiennes ; pendant dix ans n’agis pas, car rien ici n’est de quelque usage.","Regarder vers le bas pour se nourrir porte fortune ; tel un tigre qui guette d’un regard fixe et affamé, le désir est vif et pourtant sans blâme.","Te détournant du chemin ordinaire, tu demeures en repos et tiens ferme, et cela porte fortune ; mais ce n’est pas encore l’heure de traverser la grande eau.","Ici est la source d’où jaillit toute nourriture ; conscient du danger et de son poids, il y a fortune, et il est avantageux de traverser la grande eau."]},
  28: {"name":"La Prépondérance du grand","gloss":"La poutre faîtière près de rompre","judgment":"Le grand excède sa mesure : la poutre faîtière ploie sous sa charge, forte au milieu mais faible aux deux bouts. Pourtant il est avantageux d’avoir où aller, et la réussite peut encore être atteinte. Les temps extraordinaires appellent une action extraordinaire, mais bien pesée.","image":"Le lac s’élève au-dessus des arbres et les noie, image de l’excès qui presse au-delà de toute borne. Ainsi l’homme noble se tient seul sans crainte et, s’il le faut, se retire du monde sans chagrin, inébranlable dans la solitude quand les temps sont désaccordés.","lineTexts":["Tu étends de blancs joncs sous l’offrande, prenant le plus grand soin de ce que tu déposes ; une telle précaution au commencement est sans blâme.","Un peuplier flétri pousse de fraîches pousses, un vieillard prend une jeune épouse : contre toute attente, la vie se renouvelle, et tout est favorable.","La poutre faîtière fléchit jusqu’à rompre sous un poids qu’elle ne peut porter ; obstiné et sans secours, cela porte l’infortune.","La poutre faîtière est étayée et se dresse ferme, et il y a fortune ; mais si quelque autre dessein se cache au-dedans, cela porte l’humiliation.","Un peuplier flétri donne des fleurs, une vieille femme prend un jeune époux : nul blâme, peut-être, mais nulle louange durable, car la floraison ne saurait durer.","On s’avance dans l’eau jusqu’à ce qu’elle se referme sur la tête ; infortune, et pourtant nul blâme, car la perte fut consentie au service de ce qui était juste."]},
  29: {"name":"L’Insondable","gloss":"Couler fidèle à travers les profondeurs","judgment":"L’abîme répété, danger sur danger. Si tu es sincère et laisses le cœur couler sans rupture, il y a réussite au sein même du péril, et tout ce que tu entreprends sera honoré. Va comme va l’eau, fidèle à son cours, et la voie de la traversée apparaîtra.","image":"L’eau coule sans fin, toujours parvenant, emplissant chaque creux avant de poursuivre ; voici l’image du danger redoublé. Ainsi l’homme noble se tient fidèle à la vertu à travers toute profondeur et enseigne en répétant l’ouvrage, afin que ce qui est appris prenne et tienne.","lineTexts":["Pris dans l’abîme au sein de l’abîme, tombé dans la fosse la plus profonde ; voici l’infortune, car on a perdu entièrement la voie.","Le danger presse de toutes parts ; ne cherche que le plus petit gain, fais un pas assuré, et ne tente pas encore la grande évasion.","De quelque côté que tu te tournes, abîme rencontre abîme ; danger devant et danger derrière, alors fais halte et n’agis point, de peur de t’enfoncer plus avant.","Une cruche de vin, un bol de riz, simples vases passés par la fenêtre en toute sincérité ; à la fin, il n’y a nul blâme.","L’abîme n’est pas encore empli à déborder ; ne le nivelle qu’au ras du bord et ne va pas au-delà, et il n’y aura nulle faute.","Lié de cordes et de liens et jeté parmi les ronces, enfermé trois longues années sans trouver le chemin ; infortune."]},
  30: {"name":"Ce qui s’attache","gloss":"La lumière qui s’attache au vrai","judgment":"Ce qui s’attache trouve sa nature en se tenant à ce qui est juste ; demeurer dévoué porte la réussite. Soigner la vache porte fortune, car une force douce et fiable entretient la flamme. Que ton éclat repose sur ce qui est vrai, et il durera.","image":"Une double clarté, feu allumé sur feu, la grande lumière renouvelée sans fin. Ainsi l’homme grand, en prenant ceci pour modèle, laisse une clarté illuminante rayonner vers les quatre régions du monde.","lineTexts":["Les pas tombent croisés et confus au commencement du jour ; avance avec respect et soin, et tu demeures sans blâme.","Une clarté jaune, la lumière du centre équilibré : voici la fortune suprême.","Dans la lueur du soleil couchant, on bat le pot et l’on chante, ou bien l’on déplore à voix haute la venue de la vieillesse ; l’infortune gît dans l’attachement à ce qui doit s’éteindre.","Sa venue est soudaine, flambant haut, puis retombant, rejeté aussi vite qu’il s’est embrasé ; un tel feu sans mesure ne saurait durer.","Les larmes coulent à flots et le chagrin monte en soupirs ; pourtant, à travers cette douleur, le cœur se purifie, et la fortune s’ensuit.","Le roi envoie ses armées, et il y a du mérite dans la campagne ; il frappe les chefs, épargne ceux qui n’ont fait que suivre, et demeure sans blâme."]},
  31: {"name":"L’Influence","gloss":"Les cœurs attirés par le sentiment ouvert","judgment":"L’influence réciproque porte la réussite, et la constance est récompensée. Prendre une jeune fille pour épouse porte fortune, car la rencontre est consentie et l’attrait est vrai. Quand l’immobilité d’en bas s’ouvre à la joie d’en haut, les cœurs de toutes choses s’attirent.","image":"Sur la montagne repose le lac, le ferme accueillant le souple, le haut s’abaissant pour le recevoir ; voici l’image de l’influence. Ainsi l’homme noble garde l’esprit ouvert et accueillant, afin que les sentiments d’autrui puissent librement entrer et prendre racine.","lineTexts":["L’influence ne remue que dans le gros orteil ; l’impulsion est faible et demeure au-dedans, pas encore assez pour mettre quoi que ce soit en mouvement.","L’influence atteint les mollets des jambes ; se précipiter en avant maintenant porte l’infortune, mais demeurer en repos porte fortune.","L’influence meut les cuisses, qui ne font que suivre où le corps les mène ; se mettre en route ainsi, suspendu à autrui, porte l’humiliation.","La persévérance porte fortune et le regret se dissout ; mais si le cœur vacille et que les pensées vont et viennent dans une agitation sans repos, peu d’amis suivront ton dessein errant.","L’influence atteint la nuque, raide et hors de portée du cœur ; le sentiment est superficiel, mais ici du moins il n’y a nul motif de regret.","L’influence se montre dans les mâchoires, les joues, la langue, en simples paroles et persuasions ; rien que des mots, sans mouvement plus profond derrière eux."]},
  32: {"name":"La Durée","gloss":"La persévérance inébranlable à travers le changement","judgment":"La durée porte la réussite, et il n’y a nul blâme en elle ; la constance est récompensée. Il est avantageux d’avoir où aller, car ce qui dure n’est pas l’immobilité mais le mouvement régulier qui se renouvelle lui-même. Tiens ton cap, et il te portera loin.","image":"Le tonnerre en haut et le vent en bas, chacun éveillant et soutenant l’autre en union durable ; voici l’image de la durée. Ainsi l’homme noble se tient ferme et ne se détourne pas de la direction une fois choisie, persévérant à travers tout changement.","lineTexts":["Cherchant une profonde durée trop tôt et trop fort dès le tout début, tu réclames la permanence avant son heure ; persister ainsi porte l’infortune, et rien n’est gagné.","Le regret s’évanouit ici, car tu te tiens au centre durable et ta force est à la mesure du moment.","Si tu ne donnes pas à ta vertu une demeure stable, la honte te trouvera sûrement ; se tenir à une telle inconstance n’apporte que déshonneur.","Il n’y a nul gibier dans les champs, car tu as chassé là où il n’y a rien à trouver ; la constance dépensée au mauvais endroit ne rapporte rien.","Se tenir fermement à un cours unique porte fortune à l’épouse, qui suit avec constance jusqu’au bout, mais infortune à l’époux, qui doit juger chaque affaire à neuf.","La durée tenue dans une agitation sans repos, sans cesse remuée et jamais apaisée, porte l’infortune ; ce qui ne peut reposer ne peut vraiment durer."]},
  33: {"name":"La Retraite","gloss":"Céder du terrain pour préserver la force","judgment":"La Retraite réussit lorsqu’elle vient à l’heure juste. L’obscur monte d’en bas, et le fort cède le terrain non par défaite, mais par un retrait mesuré. Reculer au moment opportun préserve la force ; même dans les petites choses, la persévérance est récompensée.","image":"Le Ciel au-dessus de la Montagne : le ciel se retire tandis que la cime s’élance, lointain et hors d’atteinte. Ainsi l’homme noble tient l’homme vulgaire à distance, non par colère mais par une réserve digne, ferme et sans rancune.","lineTexts":["À la queue de la retraite, demeurer en arrière comporte un danger. Ici l’on ne doit pas se porter en avant, mais rester immobile et ne rien entreprendre.","Il est lié à son dessein par le cuir d’un bœuf jaune, et nul ne peut en desserrer l’étreinte. Une résolution aussi ferme ne saurait être arrachée.","Une retraite entravée par les attachements engendre le trouble et la lassitude. Garder serviteurs et dépendants auprès de soi peut apporter un peu de bonheur, mais ne convient pas aux grandes affaires.","L’homme supérieur se retire de bon gré et trouve le bonheur ; l’homme vulgaire, qui s’accroche, ne le peut. Lâcher prise nettement est la marque de la force.","Une retraite amicale, juste et bien menée, apporte le bonheur. Il se retire tandis que les rapports sont encore cordiaux, ne laissant rien d’aigri derrière lui.","Une retraite sereine et déliée, libre de tout doute. Là où le cœur est léger et la voie dégagée, tout est favorable."]},
  34: {"name":"La Puissance du Grand","gloss":"La grande force tenue dans de justes bornes","judgment":"La Puissance du Grand favorise la persévérance. La force s’est élevée à sa plénitude, mais la grandeur ne réside pas dans la force seule ; elle doit demeurer unie à ce qui est juste. La puissance qui sert la justice perdure, tandis que la puissance pour elle-même se défait elle-même.","image":"Le Tonnerre au-dessus du Ciel : la puissance qui roule au-dessus du firmament, vaste et retentissante. Ainsi l’homme noble ne foule aucun chemin qui ne s’accorde à l’ordre, refusant de poser le pied là où la mesure l’interdit.","lineTexts":["La puissance se manifeste dans les orteils, se précipitant avidement en avant. Avancer maintenant porterait malheur ; l’élan dépasse les moyens.","La persévérance apporte le bonheur. Le trait fort tient son centre, sans forcer en avant ni reculer, et garde ainsi sa mesure.","L’homme vulgaire se fie à la force brute ; l’homme supérieur ne le fait pas. Un bélier donne de la tête contre une haie et y prend ses cornes, perdu par son propre élan.","La persévérance apporte le bonheur, et le repentir s’évanouit. La haie cède et les cornes se libèrent ; la grande force se meut comme l’essieu d’un lourd chariot, avançant sans effort.","Il perd le bélier avec aisance, sans remords. Quand la douceur remplace la force obstinée, ce qui était tenu trop serré se relâche sans dommage.","Le bélier donne de la tête contre la haie et ne peut plus bouger ni en avant ni en arrière. Voir clairement la difficulté et la supporter apporte, à la fin, le bonheur."]},
  35: {"name":"Le Progrès","gloss":"Le soleil levant, la clarté qui s’avance","judgment":"Le Progrès : tel un puissant prince comblé de chevaux en abondance, reçu en audience trois fois en un seul jour. La lumière s’élève claire au-dessus de la terre, et celui qui sert fidèlement est reconnu et élevé. Une ascension aisée et rapide suit lorsque la dévotion rencontre un soleil accueillant.","image":"Le Feu au-dessus de la Terre : le soleil monte au-dessus de l’horizon, et sa lumière croît à mesure qu’il s’élève. Ainsi l’homme noble fait briller sa propre vertu lumineuse, polissant la clarté intérieure jusqu’à ce qu’elle rayonne d’elle-même.","lineTexts":["Progresser, et pourtant repoussé. Demeurer ferme apporte le bonheur ; si la confiance n’est pas encore accordée, reste calme et sans hâte, et nul blâme ne s’attache à toi.","Progresser, et pourtant dans l’affliction. La persévérance apporte le bonheur, et l’on reçoit une grande bénédiction de la source maternelle d’en haut.","Tous sont d’accord, et le repentir disparaît. Quand beaucoup s’avancent ensemble dans la confiance, la voie s’ouvre sans entrave.","Progresser comme un hamster, avide et furtif. Persister sur une telle voie, si bien qu’elle semble aller, attire le danger.","Le repentir s’évanouit ; ne te soucie ni de perte ni de gain. Avancer ouvertement apporte le bonheur, et rien n’est sans profit.","Progresser avec les cornes, dont on n’use que pour châtier sa propre cité. Tourner cette force au-dedans est dangereux, mais apporte le bonheur sans blâme ; la persévérance seule laisse une trace de regret."]},
  36: {"name":"L’Obscurcissement de la Lumière","gloss":"Cacher la lumière intérieure dans les ténèbres","judgment":"Dans l’Obscurcissement de la Lumière, il est favorable de persévérer à travers l’épreuve. La clarté est blessée et refoulée sous la terre, et la voie sage est de voiler son éclat et de tenir bon au-dedans. Garder sa lumière cachée en un temps obscur est en soi la voie qui mène au travers.","image":"La Terre au-dessus du Feu : la clarté s’est enfoncée au cœur du sol, son rayonnement recouvert. Ainsi l’homme noble, gouvernant la multitude, voile sa propre clarté et demeure pourtant illuminé au-dedans.","lineTexts":["L’obscurcissement de la lumière dans le vol : il abaisse ses ailes. L’homme noble, en voyage, passe trois jours sans manger ; là où il parvient, l’hôte a des paroles contre lui, mais il poursuit son dessein.","L’obscurcissement de la lumière le blesse à la cuisse gauche. Il se sauve par la force d’un cheval rapide, et le bonheur suit le secours.","L’obscurcissement de la lumière, chassant au sud, saisit le grand chef des ténèbres. Il ne faut pas espérer tout remettre en ordre trop vite.","Pénétrant profond dans le côté gauche du ventre, il atteint le cœur même de l’obscur, et là en discerne la vraie nature. Aussi prend-il congé par la porte et la cour.","L’obscurcissement de la lumière, comme il en fut du prince Ki. La persévérance est favorable ; il dissimule sa lumière, mais garde sa volonté intacte.","Non la lumière, mais les ténèbres. Il monta d’abord jusqu’aux cieux, puis sombra dans les profondeurs de la terre, et la grande clarté tomba tout entière."]},
  37: {"name":"La Famille","gloss":"L’ordre au sein de la maisonnée","judgment":"Pour la Famille, la persévérance de la femme est favorable. Quand chacun se tient fidèle à sa juste place, la maisonnée demeure ferme, et d’un foyer bien ordonné découle au-dehors le juste ordre du monde. La dévotion intérieure, fidèlement gardée, est la racine de tout ce qui dure.","image":"Le Vent au-dessus du Feu : la flamme engendre le vent, et la chaleur se répand au-dehors depuis le foyer. Ainsi l’homme noble rend ses paroles substantielles et sa conduite durable, sachant que l’influence commence à la maison.","lineTexts":["Ferme retraite au sein de la famille ; le repentir disparaît. Poser de claires limites dès le début, avant que les mauvaises habitudes ne s’enracinent, garde la maisonnée intègre.","Elle ne doit pas suivre ses propres caprices, mais veiller à la nourriture de la maison. Une dévotion paisible à l’œuvre qui lui revient apporte le bonheur par la persévérance.","Quand les humeurs s’échauffent trop dans la famille, le regret et le danger suivent, et pourtant le bonheur demeure. Si femmes et enfants ne font que rire et badiner, la voie se perd à la fin.","Elle est le trésor de la maison, la source de sa richesse. Un grand bonheur vient de celle qui enrichit le foyer par un soin constant.","Tel un roi, il s’approche de sa famille ; qu’il n’y ait nulle inquiétude, car le bonheur l’accompagne. Là où l’amour règne sans crainte, tous sont en paix.","Son œuvre commande une confiance durable et une dignité paisible. À la fin cela apporte le bonheur, car la sincérité menée à terme gagne le respect."]},
  38: {"name":"L’Opposition","gloss":"L’éloignement qui aspire encore aux retrouvailles","judgment":"Dans l’Opposition, les petites affaires apportent le bonheur. Quand les volontés sont divisées et que règne l’éloignement, les grandes entreprises ne peuvent réussir, mais dans les moindres choses l’accord peut encore se trouver. Même là où les natures diffèrent, un terrain commun demeure pour qui le cherche.","image":"Le Feu au-dessus du Lac : la flamme s’élève tandis que l’eau s’abaisse, les deux à jamais s’écartant l’un de l’autre. Ainsi l’homme noble, au milieu de toute communauté, préserve sa propre différence, s’unissant aux autres tout en demeurant lui-même.","lineTexts":["Le repentir disparaît. Si tu perds ton cheval, ne le poursuis pas ; il reviendra de lui-même. Quand tu rencontres des hommes méchants, garde-toi des fautes, et nul blâme ne demeure.","On rencontre son seigneur dans une ruelle étroite. Il n’y a nul blâme en une telle rencontre fortuite, quand tous deux inclinent vers les retrouvailles.","On voit le chariot tiré en arrière, les bœufs arrêtés, l’homme privé de ses cheveux et de son nez. Nul bon commencement, mais une bonne fin à la fin.","Isolé par l’opposition, on rencontre une âme apparentée et l’on s’unit à elle en toute bonne foi. Bien que la situation soit périlleuse, nul blâme ne demeure.","Le repentir disparaît. Le compagnon perce de ses dents les enveloppes ; si tu vas vers lui, comment serait-ce une faute ?","Isolé par l’opposition, on voit le compagnon comme un porc couvert de boue, un chariot rempli de démons. D’abord il bande l’arc, puis le dépose ; ce n’est pas un brigand, mais un prétendant. Allant de l’avant, il rencontre la pluie, et le bonheur vient."]},
  39: {"name":"L’Obstacle","gloss":"Arrêté devant une voie ardue","judgment":"L’Obstacle : le sud-ouest est favorable, le nord-est ne l’est pas. Il est favorable de voir le grand homme, et la persévérance apporte le bonheur. Quand la route est barrée devant soi, ne force pas le passage ; tourne-toi au-dedans, cherche un sage conseil, et la voie s’ouvrira en son temps.","image":"L’Eau au-dessus de la Montagne : le danger de la crue rencontre la barrière de la cime, et le chemin s’arrête devant une double difficulté. Ainsi l’homme noble tourne son regard sur lui-même et travaille à façonner son propre caractère.","lineTexts":["Aller mène à l’obstacle ; revenir apporte la louange. Attendre et rebrousser chemin maintenant, plutôt que se jeter dans la difficulté, vaut l’honneur.","Le serviteur du roi rencontre obstacle sur obstacle, et pourtant ce n’est pas pour lui-même. Il ne faiblit point, car c’est le devoir, non le gain, qui le pousse en avant.","Aller mène à l’obstacle ; aussi rebrousse-t-il chemin. Ceux qui dépendent de lui se réjouissent de son retour.","Aller mène à l’obstacle ; revenir apporte l’union. Il attend, et rassemble ceux qui partageront avec lui la difficulté.","Au milieu du plus grand obstacle, des amis arrivent. Le trait ferme au centre attire les secours à ses côtés quand le besoin est le plus profond.","Aller mène à l’obstacle ; revenir apporte un grand bonheur. Il est favorable de voir le grand homme, car celui qui revient prêter sa force accomplit beaucoup."]},
  40: {"name":"La Délivrance","gloss":"L’orage éclate, la tension se relâche","judgment":"La Délivrance : le sud-ouest est favorable. S’il ne reste plus nulle part où aller, le retour apporte le bonheur ; s’il reste encore quelque part où aller, alors la hâte apporte le bonheur. Quand la tension se rompt, règle les choses promptement, puis reviens te reposer, sans nourrir de rancune.","image":"Le Tonnerre au-dessus de l’Eau : l’orage éclate, le tonnerre roule, et la tension de l’air se relâche en une pluie purifiante. Ainsi l’homme noble pardonne les fautes et remet les torts, laissant l’air s’éclaircir et le fardeau tomber.","lineTexts":["Sans blâme. À l’instant de la délivrance, on repose dans le calme ; il n’est plus rien à dire ni à faire.","Il tue trois renards dans les champs et reçoit une flèche jaune. La persévérance apporte le bonheur à celui qui écarte la ruse trompeuse et tient le juste milieu.","Un homme porte un fardeau sur le dos, mais voyage en char, tentant les brigands de s’approcher. Un tel étalage déplacé, si justifié soit-il, apporte l’humiliation.","Délivre-toi de l’orteil auquel tu t’accroches ; alors le vrai compagnon vient, et en lui tu peux te fier. Lâcher les basses attaches attire les amis dignes.","Si l’homme noble se délivre, le bonheur suit, et même les hommes vulgaires sont gagnés. Quand le cœur est vraiment délivré, les esprits mesquins s’écartent d’eux-mêmes.","Le prince tire sur un faucon perché au haut d’une muraille et l’abat. Rien qui ne soit favorable ; l’obstacle est ôté d’un seul coup, bien préparé."]},
  41: {"name":"La Diminution","gloss":"Le moins, offert avec sincérité","judgment":"Ce qu’on retranche en bas pour enrichir le haut peut encore porter sa bénédiction, si la diminution se fait dans la sincérité. Une offrande simple, donnée d’un cœur droit, vaut mieux qu’une offrande somptueuse donnée sans lui. Quand on exige moins de soi, la voie s’ouvre devant soi et toute entreprise trouve son profit.","image":"La Montagne se tient au-dessus du Lac, et son poids attire vers le bas l’eau retenue en dessous. Ainsi l’homme noble réfrène sa colère et modère ses appétits, amenuisant au-dedans ce qui enfle trop librement. Diminuer le bas au service du haut, c’est affiner le tout.","lineTexts":["Laisser de côté ses propres affaires pour accourir et aider autrui n’est point une faute ; pèse d’abord, pourtant, combien tu peux justement donner.","Tenir ferme est favorable, et se mettre en marche apporterait le malheur ; on enrichit le mieux autrui en ne perdant rien de soi-même.","Quand trois cheminent ensemble, l’un s’en va ; quand un seul chemine, il trouve un compagnon. Le nombre juste revient de lui-même.","En diminuant le mal que l’on porte, on incite les autres à venir vite avec leur joie ; nul blâme.","Un tel accroissement survient que nul ne saurait l’écarter, comme si dix carapaces de tortue confirmaient la faveur ; suprême fortune.","Enrichir les autres sans rien leur prendre est le plus haut des gains ; on trouve partout des serviteurs, et la maison n’est plus une barrière."]},
  42: {"name":"L’Augmentation","gloss":"L’abondance généreuse mise en mouvement","judgment":"Il est avantageux d’entreprendre quelque chose, et traverser la grande eau apporte sa récompense. Quand ceux d’en haut donnent librement à ceux d’en bas, le peuple se réjouit sans mesure et l’œuvre prospère. C’est la saison du mouvement et de l’entreprise hardie et généreuse.","image":"Le Vent souffle en haut et le Tonnerre s’éveille en bas, chacun fortifiant l’autre, en sorte que leur force se multiplie. Ainsi l’homme noble, voyant le bien chez autrui, se hâte de l’imiter, et trouvant en lui-même un défaut, s’applique aussitôt à le corriger. Ainsi croît-on sans cesse.","lineTexts":["Voici le temps de tenter de grandes choses ; suprême fortune s’ensuit, et nul blâme, car la force vient d’en haut.","Un tel accroissement arrive que nul ne peut le repousser, comme dix carapaces de tortue le confirment ; la constance porte fortune, et même l’offrande au plus haut est bénie.","L’accroissement parvient par des événements malheureux, mais il n’y a nul blâme si tu demeures sincère et marches sur la voie du milieu, faisant au prince un rapport sans détour.","En marchant sur la voie du milieu, ton conseil est écouté du prince ; tu peux t’appuyer sur lui pour mettre le peuple en mouvement et déplacer le siège du pouvoir.","Si un cœur sincère et bienveillant te guide, ne demande rien en retour ; suprême fortune, car ta bonté est elle-même reconnue pour ta valeur.","Il n’apporte d’accroissement à personne, et certains le frappent même ; son cœur n’est pas ferme, et le malheur survient."]},
  43: {"name":"La Percée","gloss":"Le rejet résolu de ce qui doit tomber","judgment":"L’affaire doit être portée résolument à la cour, nommée ouvertement et selon la vérité. Pourtant le danger demeure ; n’ameute que ta propre cité et ne saisis pas les armes à la hâte. Il est avantageux d’avoir un but vers lequel s’avancer, mais la résolution doit être tempérée de prudence.","image":"Le Lac s’est élevé jusqu’au Ciel et le presse, et ses eaux doivent rompre et retomber. Ainsi l’homme noble dispense ses richesses à ceux d’en bas et fuit la thésaurisation qui élève trop haut. Ce qui s’amasse au-delà de sa mesure doit être relâché avant d’éclater.","lineTexts":["Fort dans les orteils qui s’avancent, tu vas de l’avant ; mais si tu ne peux l’emporter, l’entreprise tourne au blâme.","Vigilant et criant l’alarme à travers la nuit, tu n’as rien à craindre, car tu es armé contre le danger qui vient.","La force se montre aux pommettes et apporte le malheur ; l’homme noble chemine seul sous la pluie, souillé et mal vu, mais à la fin sans blâme.","Il n’y a plus de peau aux cuisses, et la marche est chancelante ; mené comme un mouton, le regret s’évanouirait, mais l’avertissement n’est pas cru.","Les mauvaises herbes doivent être sarclées d’une décision ferme ; marche sur la voie du milieu, et il n’y a nul blâme.","Nul cri d’alarme ne s’élève, et à la fin vient le malheur ; le dernier petit reste du mal ne doit pas être négligé."]},
  44: {"name":"La Rencontre","gloss":"Le petit revient, non convié, à la rencontre","judgment":"Une seule force cédante est revenue et pousse vers le haut parmi les fermes ; elle est hardie, et l’on ne saurait prendre telle jeune fille pour épouse. Ce qui semble une petite et bienvenue rencontre peut s’étendre jusqu’à tout envahir ; ne te lie pas à ce qui ne peut être durablement tenu.","image":"Le Ciel se tient au-dessus du Vent, qui se meut sous lui et porte la parole du prince en tout recoin du pays. Ainsi le souverain répand ses ordres au loin et les fait connaître aux quatre directions. Ce qui rencontre toutes choses doit parler à toutes choses.","lineTexts":["Il faut l’arrêter d’un frein de bronze dès le commencement ; persévère et la fortune vient, mais laisse-le courir libre, et un porc maigre s’agitera follement.","Il y a un poisson dans le vivier ; nul blâme, mais il ne convient pas de l’offrir aux hôtes.","Il n’y a plus de peau aux cuisses, et la marche est chancelante ; reste attentif au danger et nulle faute grave ne s’ensuivra.","Il n’y a pas de poisson dans le vivier ; de ce vide naîtra le malheur, car le lien avec ceux d’en bas a été laissé rompre.","Un melon est abrité sous des feuilles de saule ; des traits cachés de valeur sont gardés, et ce qui est destiné descendra du ciel de soi-même.","Il vient à la rencontre avec ses cornes, raides et distantes ; il y a humiliation, mais nul vrai blâme ne demeure."]},
  45: {"name":"Le Rassemblement","gloss":"La multitude attirée vers un seul centre","judgment":"Quand le rassemblement réussit, le roi s’approche de son temple, et il est avantageux de voir le grand homme. Apporte une grande offrande, car grande est la fortune en une telle union ; il est bon d’avoir un dessein et de s’avancer vers lui. Là où beaucoup se réunissent, il faut un être vers qui l’on se rassemble.","image":"Le Lac repose sur la Terre et recueille ses eaux en un seul corps resplendissant. Ainsi l’homme noble tient ses armes en bon état, prêtes contre l’imprévu, car là où les foules s’assemblent peuvent naître et l’harmonie et la discorde. Veille sur le rassemblement avant que le trouble ne s’y agite.","lineTexts":["Ta sincérité vacille et le rassemblement tombe dans la confusion ; crie, et une seule étreinte de main change la plainte en rire. Va de l’avant sans crainte ; nul blâme.","Laisse-toi entraîner, et la fortune suit sans blâme ; une petite offrande sincère, faite avec simplicité, suffit.","Se rassembler parmi les soupirs, sans rien de favorable en vue ; va de l’avant néanmoins, car il n’y a nul blâme, seulement un peu d’humiliation.","Grande fortune, et avec elle nul blâme, quand on rassemble les autres non pour soi mais pour le bien commun.","Si tu tiens une haute place dans le rassemblement, il n’y a nul blâme ; mais là où la confiance n’est pas encore gagnée, seule une grande et durable constance fait dissoudre le regret.","Se lamentant et soupirant, les larmes ruisselant ; nul blâme, car ceux qui s’affligent d’être exclus du rassemblement y trouvent enfin leur place."]},
  46: {"name":"La Poussée vers le haut","gloss":"La montée régulière, comme croît l’arbre","judgment":"La poussée vers le haut apporte un suprême succès ; il faut chercher le grand homme et n’avoir nulle inquiétude. S’avancer vers le sud est favorable, et l’ascension est récompensée. Élève-toi doucement et sans relâche, comme une chose qui croît, et la voie cédera.","image":"Au sein de la Terre, le Bois croît et s’élève, se haussant lentement vers la lumière. Ainsi l’homme noble, par son dévouement au bien, rassemble les petites choses et entasse ainsi le grand et le haut. La grandeur ne s’atteint pas d’un bond mais par accumulation.","lineTexts":["S’élever dans la confiance et être accueilli vers le haut ; grande fortune, car l’ascension commence sur un sol consentant.","Si la sincérité est tienne, même une petite et simple offrande est agréée ; nul blâme.","Tu montes dans une cité vide, ne trouvant nulle résistance devant toi.","Le roi fait son offrande sur la montagne sacrée ; fortune et nul blâme, car l’ascension est consacrée.","La persévérance apporte la fortune tandis que tu montes degré par degré sur les marches.","Monter aveuglément dans l’obscurité ; cela n’est avantageux que dans une constance vigilante et sans relâche, de peur que la montée ne perde son chemin."]},
  47: {"name":"L’Accablement","gloss":"La force tenue ferme dans l’adversité","judgment":"L’épuisement peut encore mener au succès, et pour l’homme ferme et grand il y a fortune et nul blâme. Mais en un tel temps les paroles ne sont pas crues ; qui parle beaucoup n’est pas écouté. Que la force de l’esprit, non la protestation, te porte à travers le détroit.","image":"Le Lac se tient au-dessus de l’Eau, mais l’eau s’est écoulée en dessous et l’a laissé sec et stérile. Ainsi l’homme noble joue sa vie pour suivre sa volonté, sans se laisser abattre quand la fortune manque et que les sources se tarissent. Quand tout est ôté, la résolution intérieure demeure.","lineTexts":["Assis, accablé sous un arbre nu et desséché, on s’égare dans une vallée sombre et durant trois ans on ne voit personne.","Accablé au milieu du vin et des mets, mais les ceintures écarlates de la charge approchent ; il est avantageux de faire une offrande, et se mettre en marche apporterait le malheur, quoique sans blâme.","Pressé contre les pierres, se cramponnant aux ronces ; il entre dans sa maison et n’y trouve pas sa femme. Malheur.","Il vient très lentement, accablé dans un char d’or ; il y a humiliation, mais l’affaire atteint son terme.","Le nez et les pieds tranchés, accablé par l’homme à la ceinture pourpre ; la joie vient lentement, et il est avantageux de faire la calme offrande.","Accablé par les vignes rampantes, vacillant sur une hauteur incertaine ; s’il dit : « le mouvement apporte le remords », et se repent, alors aller de l’avant apporte la fortune."]},
  48: {"name":"Le Puits","gloss":"La source immobile qui nourrit tout","judgment":"On peut déplacer la ville, mais on ne peut déplacer le puits ; il ne diminue ni ne déborde, et tous ceux qui vont et viennent y peuvent puiser. Mais si l’on atteint presque l’eau et que la corde manque, ou que l’on brise la cruche, il y a malheur. Ce qui nourrit tous demande que l’on mène le puisage jusqu’à son terme.","image":"L’Eau repose sur le Bois, qui descend dans les profondeurs et l’en relève. Ainsi l’homme noble encourage le peuple dans son labeur et l’exhorte à s’entraider. La source est constante ; seul le puisage doit être soigné.","lineTexts":["Le puits est obstrué de boue et nul n’y boit ; un vieux puits où même les oiseaux ne viennent plus.","À l’ouverture du puits on ne tire que sur les poissons d’en bas ; la cruche est fêlée et laisse fuir son eau.","Le puits est curé, mais nul n’y boit ; cela afflige le cœur, car l’eau pourrait être tirée. Si seulement le roi était clairvoyant, tous pourraient partager la bénédiction.","Le puits est revêtu de pierre ; il n’y a nul blâme, car le travail qui répare la source est bien employé.","Le puits renferme une source claire et fraîche, et l’on peut y boire.","On puise au puits librement et jamais on ne le couvre ; là réside la sincérité et la suprême fortune."]},
  49: {"name":"La Révolution","gloss":"Muer pour quitter la vieille peau","judgment":"La révolution n’obtient la confiance que lorsque son heure est venue ; précipitée, elle n’éveille que le soupçon, mais attendue jusqu’au jour de la maturité, le changement est cru. Un grand succès s’ensuit, et ce qui est ferme et juste demeure. Alors tout motif de regret s’efface.","image":"Le Lac se tient au-dessus du Feu, l’eau et la flamme en lutte irréconciliable, chacune transformant l’autre. Ainsi l’homme noble met le calendrier en ordre et rend les saisons claires, lisant la marche du temps afin que le changement vienne au pas de l’heure.","lineTexts":["Lié fermement dans le cuir d’un bœuf jaune ; rien encore ne peut être entrepris, car le moment d’agir n’est pas arrivé.","Quand enfin le jour propice survient, mets le changement en mouvement. Aller de l’avant maintenant apporte la bonne fortune et ne laisse derrière soi aucune faute.","Pousser la révolution avec trop de hâte appelle l’infortune, mais la lenteur craintive est elle aussi périlleuse. Quand la parole de changement a fait trois fois le tour, alors elle porte la confiance et peut être suivie.","Le remords s’évanouit, car le peuple maintenant croit. Renverser l’ordre ancien à cette heure apporte la bonne fortune.","Le grand homme se transforme comme le tigre dont les rayures fraîches flamboient avant qu’aucun présage ne soit jeté ; le dessin nouveau est sans équivoque et commande la confiance.","L’homme noble se transforme comme la panthère, affinant les marques de l’ordre nouveau ; les êtres médiocres ne font que recomposer leur visage. Aller plus loin maintenant apporterait l’infortune, mais demeurer dans le juste apporte la bonne fortune."]},
  50: {"name":"Le Chaudron","gloss":"Le vase qui nourrit le sacré","judgment":"Le Chaudron annonce la plus haute fortune et apporte le succès. Il est le vase où le cru se transforme en nourriture digne du sacré et des sages. Là où la révolution abat l’ancien, le chaudron consacre le nouveau.","image":"Le Feu repose au-dessus du Vent, le vent nourrissant la flamme sous le vase comme le bois nourrit le feu où l’on cuit. Ainsi l’homme noble affermit la juste station et consolide le destin, tenant ferme à la place que le sort lui a assignée.","lineTexts":["Le chaudron est renversé pour vider son vieux résidu. Comme on écarte une concubine usée pour l’amour d’un fils, ce qui semble ici déplacé sert à chasser ce qui est rance ; aucune faute.","Le chaudron est rempli de substance. Mes compagnons sont jaloux, mais ils ne peuvent m’atteindre ; bonne fortune, car l’ouvrage est solide.","L’anse du chaudron est changée et son transport entravé ; la graisse riche du faisan reste sans être mangée. Mais quand la pluie tombe, la tension se dissout, et à la fin il y a bonne fortune.","Les pieds du chaudron se brisent et le repas du prince se répand, le contenu souillé. Voilà la honte, et l’infortune, car on n’était pas à la hauteur de la charge confiée.","Le chaudron a des anses jaunes et des anneaux d’or. Il convient de rester ferme et correct, car les moyens de porter l’œuvre sont désormais sûrs.","Le chaudron a des anneaux de jade, lustrés et solides. Grande bonne fortune ; il ne reste rien qui ne favorise la voie."]},
  51: {"name":"L’Éveilleur","gloss":"Le coup de tonnerre qui réveille","judgment":"Le choc survient et apporte le succès. Quand le tonnerre éclate, le cœur tremble de terreur, mais ensuite viennent le rire et la parole légère. Le choc répand l’effroi sur cent lieues, mais celui qui veille sur le vase sacré ne laisse tomber ni la louche ni le calice.","image":"Le tonnerre roule sur le tonnerre, coup répondant à coup à travers le ciel. Ainsi l’homme noble, dans la crainte et le tremblement, met sa vie en ordre et s’examine au-dedans.","lineTexts":["Le choc survient et le cœur défaille, mais ensuite viennent le rire et l’aisance. Bonne fortune, car l’effroi a éveillé une prudence salutaire.","Le choc arrive porteur de danger, et l’on tient le trésor pour perdu en fuyant vers les hauteurs. Ne cours pas après ce qui est parti ; au septième jour, il revient de lui-même.","Le choc survient et laisse hébété et chancelant. Si l’alarme met en mouvement vers le juste, aucune infortune n’en découle.","Le choc survient, et l’on est embourbé, enlisé dans un sol mou ; rien ne peut bouger tant que l’esprit reste enfoncé.","Le choc va et vient, allant et venant avec le danger de tous côtés. Pourtant rien n’est vraiment perdu ; veille à l’ouvrage qui ne doit pas être négligé.","Le choc apporte la ruine et un égarement hagard ; aller de l’avant maintenant est infortune. Puisque le coup tombe sur le voisin et non encore sur soi, il n’y a pas de faute à se retenir, même si les proches murmurent."]},
  52: {"name":"L’Immobilisation","gloss":"L’immobilité qui connaît sa propre limite","judgment":"Tenir immobile le dos, en sorte que le moi ne se sente plus ; traverser la cour sans apercevoir les gens qui s’y trouvent. Reposer là où le repos a sa place et se mouvoir là où le mouvement a la sienne, l’esprit en paix avec sa propre limite. Il n’y a pas de faute.","image":"La Montagne repose sur la Montagne, l’immobilité redoublée et sans mouvement. Ainsi l’homme noble retient ses pensées d’errer au-delà du lieu présent, gardant l’esprit dans l’instant qu’il habite.","lineTexts":["Tenir les orteils immobiles, avant que le premier pas ne soit fait. Aucune faute ; il est favorable de demeurer durablement ferme.","Tenir les mollets immobiles, mais le mollet ne peut retenir la jambe qu’il suit ; on est entraîné contre son gré, et le cœur est mal à l’aise.","Tenir les hanches immobiles, raidissant les reins jusqu’à ce que le sacrum se déchire ; une retenue si rigide et grinçante étouffe le cœur de péril.","Tenir le tronc immobile, le corps au repos. Aucune faute, bien que le calme ne soit pas encore celui de tout l’être.","Tenir les mâchoires immobiles, en sorte que les paroles soient mesurées et ordonnées. Le remords disparaît.","L’immobilité au cœur noble, le silence de celui qui repose dans l’achèvement. Bonne fortune."]},
  53: {"name":"Le Progrès graduel","gloss":"La montée lente et sûre de l’oie sauvage","judgment":"Le développement se déploie comme la jeune fille qu’on donne en mariage, pas à pas, par degrés ; bonne fortune. Ce qui mûrit lentement prend racine durablement, et ainsi il est favorable de persévérer dans le juste. Rien de valeur ne s’obtient par la hâte.","image":"Le Vent se meut au-dessus de la Montagne, l’arbre s’étendant lentement sur la hauteur, croissant seulement à mesure que les années le permettent. Ainsi l’homme noble demeure dans le mérite et la vertu, affinant ses manières par degrés jusqu’à ce que les mœurs du peuple s’améliorent.","lineTexts":["L’oie sauvage s’approche peu à peu de la rive. Le jeune est en péril et l’on murmure contre lui, mais il n’y a pas de faute.","L’oie sauvage s’approche peu à peu de la corniche ; mangeant et buvant dans une joie tranquille, tout est à l’aise. Bonne fortune.","L’oie sauvage s’approche peu à peu du haut plateau. L’homme part en campagne et ne revient pas ; la femme conçoit mais n’enfante pas. Infortune ; ici il est favorable de repousser l’attaque.","L’oie sauvage s’approche peu à peu de l’arbre et trouve peut-être une branche plate où se poser. Aucune faute, car elle accepte avec patience une place qui n’est pas la sienne.","L’oie sauvage s’approche peu à peu du sommet. Pendant trois ans la femme n’a pas d’enfant, mais à la fin rien ne peut empêcher l’union ; la bonne fortune vient enfin.","L’oie sauvage s’approche peu à peu des hauteurs nuageuses, et ses plumes tombées peuvent servir à la danse sacrée. Bonne fortune ; l’ascension atteint le royaume de l’ordre et du sens."]},
  54: {"name":"La Fiancée","gloss":"La cadette qui suit","judgment":"La Fiancée entre non comme première épouse mais comme celle qui suit, attirée par l’impulsion plutôt que par le rite. Entreprendre dans cet esprit apporte l’infortune, et rien ici n’est favorisé. Il faut comprendre ce qu’une telle union a de passager et de défectueux.","image":"Le tonnerre s’agite au-dessus du Lac, l’eau joyeuse mue par la tempête qui l’éveille. Ainsi l’homme noble, sachant comment les choses finissent dans la décadence, s’attache à ce qui dure et se garde de la rupture à venir.","lineTexts":["La jeune fille se marie comme épouse de second rang, prenant une place humble ; comme un boiteux qui peut encore marcher, elle sert là où elle peut. Continuer ainsi apporte la bonne fortune.","Un borgne qui pourtant voit quelque chose. Il est favorable au solitaire de tenir à la constance, gardant la foi même dans une position dédaignée et obscure.","La jeune fille qui voudrait se marier attend dans la servitude, et ce n’est qu’en acceptant la station moindre, comme épouse subordonnée, qu’elle trouve sa voie. La fière attente ne pouvait durer.","La fiancée laisse passer le temps fixé ; un mariage tardif vient en sa propre saison. Mieux vaut attendre l’heure juste que de saisir la mauvaise.","Le souverain royal donne sa fille en mariage ; ses manches brodées sont plus simples que celles de la servante, car le vrai mérite n’a pas besoin d’apparat. La lune presque pleine est des plus favorables. Bonne fortune.","La femme tend une corbeille, mais elle est vide ; l’homme égorge le mouton, mais aucun sang ne coule. Les formes sont observées sans substance ; rien n’est favorisé."]},
  55: {"name":"L’Abondance","gloss":"Le midi débordant de la plénitude","judgment":"L’abondance apporte le succès, et le roi l’atteint à son zénith. Ne t’afflige pas que la plénitude ne puisse durer ; sois comme le soleil à midi, donnant la lumière librement tant qu’il se tient haut. Le faîte de l’opulence est bref, qu’il soit donc bien employé.","image":"Le Tonnerre et l’Éclair se rejoignent, la clarté et le mouvement unis au sommet de leur puissance. Ainsi l’homme noble tranche les procès et exécute les peines, jugeant avec éclat et agissant avec une force décisive.","lineTexts":["On rencontre le compagnon destiné, un égal en valeur ; bien qu’ils passent dix jours ensemble, ce n’est pas une faute. Aller de l’avant dans une telle union mérite reconnaissance.","Le voile de l’abondance devient si dense qu’à midi l’on voit les étoiles polaires ; insister maintenant attirerait défiance et haine. Mais que la vérité intérieure rayonne, et la bonne fortune vient.","Le fourré de l’abondance est si épais qu’à midi paraissent les plus petites étoiles ; le bras droit est brisé et ne peut agir. Aucune faute, car on est simplement empêché, non pas réticent.","La tente de l’abondance assombrit le jour jusqu’à ce que les étoiles polaires se montrent à midi, mais alors on rencontre le seigneur de même nature. La bonne fortune naît de la rencontre.","Des êtres de valeur s’avancent, apportant bénédiction et louange. Bonne fortune.","La maison enfle d’abondance jusqu’à masquer la maisonnée ; scrutant par la porte, on la trouve silencieuse et déserte, nul n’y paraît depuis trois ans. Infortune, car la grandeur s’est vidée de toute vie."]},
  56: {"name":"Le Voyageur","gloss":"L’étranger loin de chez lui","judgment":"Le Voyageur trouve un succès modeste ; dans les petites choses, la persévérance apporte la bonne fortune. L’étranger loin de chez lui n’a aucun rang sur quoi s’appuyer et doit être réservé et droit en tout ce qu’il fait. La prudence et la courtoisie sont son seul abri.","image":"Le Feu repose sur la Montagne, brûlant brièvement le long de la pente et passant outre, sans jamais s’établir là où il flambe. Ainsi l’homme noble est clair et prudent à infliger les peines et ne laisse pas les procès traîner, tranchant vite puis passant son chemin.","lineTexts":["Le voyageur s’agite pour des riens et s’occupe de futilités ; par une telle petitesse il attire sur lui le malheur.","Le voyageur arrive à une auberge et porte ses biens avec lui ; il gagne la loyauté d’un jeune serviteur fidèle, et trouve ainsi un sol ferme en terre étrangère.","Le voyageur incendie son logis et perd la loyauté de son serviteur ; persévérer maintenant n’apporte que le danger, car il a ruiné par négligence son propre abri.","Le voyageur trouve un lieu de refuge et acquiert des biens et une hache pour se protéger, mais son cœur n’est pas joyeux ; la sécurité est inquiète, car elle n’est pas vraiment sienne.","Il abat un faisan, et bien qu’une flèche soit perdue, à la fin cela lui vaut louange et haute charge. L’habileté justement montrée gagne la faveur même sur la route.","Le nid de l’oiseau brûle ; le voyageur d’abord rit, puis doit pleurer et se lamenter. Dans sa hâte il perd son bétail à la frontière. L’infortune vient à qui oublie qu’un étranger doit rester humble."]},
  57: {"name":"Le Doux","gloss":"La pénétration patiente, le vent qui ploie toute chose","judgment":"Par une influence douce et incessante, on obtient un petit succès. Il est bon d’avoir un but vers où aller, et bon de solliciter le conseil d’un homme éminent. Ce qu’on ne peut forcer se conquiert encore par une patiente pénétration.","image":"Le vent suit le vent, la brise qui ploie sans rompre et pénètre partout. Ainsi l’homme noble répand ses ordres et fait avancer l’œuvre, répétant la parole douce jusqu’à ce qu’elle prenne racine au cœur des autres.","lineTexts":["Avancer et reculer dans l’incertitude ; la résolution d’un homme discipliné raffermit la volonté qui vacille.","Le vent fouille sous le lit, là où s’amassent les choses cachées. Recourir en si grand nombre aux devins et aux prêtres apporte la fortune et nul blâme.","La pénétration répétée encore et encore n’est plus que tracas ; l’humiliation suit l’esprit trop empressé.","Ici le remords s’évanouit. À la chasse on prend trois sortes de gibier ; la poursuite patiente reçoit sa récompense.","La persévérance apporte la fortune et le remords disparaît. Il n’y a pas de commencement, mais il y a une fin ; pèse trois jours avant, trois jours après, et la fortune suit.","Le vent fouille de nouveau sous le lit, mais voici la hache et les moyens perdus. Persister apporte l’infortune."]},
  58: {"name":"Le Joyeux","gloss":"La joie qui réjouit et se partage","judgment":"La joie apporte le succès, et il est avantageux de persévérer. La vraie allégresse est ferme au-dedans et douce au-dehors, celle qui attire librement les autres vers le labeur commun. Une telle joie rend même la peine et le danger légers à porter.","image":"Des lacs reposant l’un sur l’autre, leurs eaux se mêlant et se renouvelant sans fin. Ainsi l’homme noble se joint à ses amis pour étudier et s’entretenir, afin que la joie s’approfondisse et se renouvelle en bonne compagnie.","lineTexts":["Joie sereine, paisible et sans convoitise ; la fortune accompagne le cœur en paix avec lui-même.","La joie sincère venue du dedans apporte la fortune, et tout remords se dissout.","La joie qui vient courtiser du dehors, cherchant le plaisir pour lui-même ; cela apporte l’infortune.","Pesant une joie contre une autre, ne trouvant point de repos ; mais tracer une ligne claire et se détourner de l’allégresse funeste apporte le soulagement.","Se fier à ce qui voudrait t’user porte un vrai danger ; garde-toi de la joie qui dissout ta fermeté.","La joie qui appâte et séduit, entraînant les autres par son seul charme, sans jamais se reposer dans la vérité."]},
  59: {"name":"La Dissolution","gloss":"Dissoudre la dureté qui divise","judgment":"La dissolution a le succès. Le roi s’approche de son temple, et il est avantageux de traverser la grande eau ; la persévérance apporte la récompense. Quand le vent réchauffe les eaux gelées, ce qui était rigide et divisé fond et coule de nouveau ensemble.","image":"Le vent passant sur l’eau, dispersant la glace et l’animant de mouvement. Ainsi les rois d’autrefois offraient le sacrifice aux puissances suprêmes et élevaient des temples, rassemblant les cœurs dispersés du peuple autour d’une commune vénération.","lineTexts":["Porte secours tant que la fissure est petite, et porte-le avec force, comme un cheval rapide ; la fortune vient d’agir avant que la division ne durcisse.","Quand la dissolution commence, hâte-toi vers ce qui te soutient ; le remords disparaît pour qui trouve un refuge.","Dissoudre le moi et ses menues préoccupations ; se tournant au-dehors, par-delà son propre ego, il n’y a nul regret.","Dissoudre la faction, le cercle étroit de son propre parti, apporte la fortune suprême. De la dispersion naît un rassemblement plus grand que l’esprit commun ne pouvait prévoir.","Répandre au loin de grandes proclamations comme une sueur, dissiper les richesses amassées du roi ; au temps de la dissolution, le souverain tient ferme et reste sans blâme.","Écarter le sang qui serait répandu, s’éloigner du danger et de sa portée ; à se tenir hors d’atteinte du mal, il n’y a nulle faute."]},
  60: {"name":"La Limitation","gloss":"La mesure qui donne sa forme à la vie","judgment":"La limitation apporte le succès. Mais la limitation amère et pénible ne doit pas durer ; la mesure a sa propre mesure. Comme chaque saison garde sa borne, ainsi la sage retenue façonne la vie en ordre sans cruauté.","image":"L’eau au-dessus du lac, qui ne peut en contenir qu’une certaine quantité avant de déborder. Ainsi l’homme noble établit des mesures et des degrés clairs, et réfléchit à la conduite qui s’y accorde justement.","lineTexts":["On ne franchit pas la porte de la cour ; sachant quand demeurer immobile, il n’y a nul blâme.","On ne franchit pas la porte de la cour quand le moment de partir est venu ; un tel retard apporte l’infortune.","Ne connaissant nulle limite, le cœur qui ne trouve point de borne aura sujet de se lamenter ; mais qui d’autre est à blâmer ?","Limitation sereine, retenue portée aisément et sans effort ; cela conduit au succès.","Douce limitation, gracieuse et de bon gré embrassée, apporte la fortune. Avancer dans cet esprit gagne l’honneur et l’estime.","Limitation pénible, rude et amère ; persister en elle apporte l’infortune, bien qu’avec le temps le remords puisse passer."]},
  61: {"name":"La Vérité intérieure","gloss":"La sincérité qui atteint le cœur des choses","judgment":"La vérité intérieure émeut jusqu’aux porcs et aux poissons, et apporte la fortune. Il est avantageux de traverser la grande eau, et avantageux de persévérer. Quand la sincérité emplit le cœur, elle atteint les créatures les plus obstinées et les moins conscientes.","image":"Le vent passant sur le lac, en agitant la surface du dedans afin que l’eau réponde librement. Ainsi l’homme noble pèse avec soin les causes des accusés et retient la main de la mort, laissant la compassion guider le jugement.","lineTexts":["Être préparé au-dedans apporte la fortune ; mais si l’on nourrit des desseins secrets envers autrui, le cœur ne trouve point de repos.","Une grue appelle dans l’ombre, et son petit répond ; j’ai une bonne coupe, et je la partagerai avec toi. L’accord caché des cœurs vrais n’a besoin d’aucune montre.","Trouvant un compagnon : tantôt battant le tambour, tantôt s’immobilisant, tantôt pleurant, tantôt chantant. Le cœur qui dépend tout entier d’un autre est ballotté entre l’ivresse et le chagrin.","La lune presque pleine ; le cheval d’attelage se sépare de son compagnon et poursuit seul. Quitter ses moindres compagnons et s’élever vers le plus haut est sans blâme.","Posséder une vérité qui lie les autres entre eux comme par un cordon ; la ferme sincérité maintient tout en place, et il n’y a nul blâme.","Le chant du coq qui s’efforce d’atteindre le ciel ; comment un tel vain éclat pourrait-il durer ? Son sans substance, y persister apporte l’infortune."]},
  62: {"name":"La Prédominance du Petit","gloss":"Modeste excès dans les choses petites et humbles","judgment":"Le petit l’emporte, et il y a le succès ; la persévérance est avantageuse. On peut entreprendre les petites affaires, mais non les grandes. Le chant de l’oiseau dit qu’il faut descendre plutôt que monter ; dans l’humilité est la grande fortune.","image":"Le tonnerre sur la montagne, son fracas excédant ses bornes accoutumées tout en restant contenu dans le calme de la cime. Ainsi l’homme noble penche légèrement vers l’excès dans sa conduite : un peu plus de respect dans le deuil, un peu plus d’économie dans la dépense, un peu plus de déférence dans le maintien.","lineTexts":["Un oiseau qui s’envole trop haut, au-delà de ses forces ; à trop présumer dès le début, l’infortune est rencontrée.","Dépassant l’aïeul, on rencontre l’aïeule ; n’atteignant pas le prince, on rencontre le ministre. À se tenir dans la juste mesure, il n’y a nul blâme.","Si l’on n’est pas extrêmement prudent, quelqu’un peut frapper par-derrière ; sans vigilante précaution, l’infortune suit.","Sans blâme, mais aborde la chose sans la forcer. Poursuivre apporterait le danger ; il faut tenir ferme et ne point agir, persévérant dans la retenue.","Nuages épais, et pourtant nulle pluie, dérivant du champ d’occident ; le prince tire et prend celui qui est déjà dans la grotte. Le petit ne peut mener la grande œuvre à son terme.","Dépassant la mesure et manquant le but, l’oiseau s’envolant toujours plus loin ; ceci est l’infortune, et se nomme calamité et ruine que l’on s’inflige."]},
  63: {"name":"Après l’accomplissement","gloss":"L’œuvre accomplie, et pourtant la vigilance requise","judgment":"Après l’accomplissement, le succès vient dans les petites choses, et la persévérance est avantageuse. Au commencement tout est en ordre et la fortune sourit ; mais à la fin le désordre menace. L’œuvre est faite, et pourtant le péril est désormais de croire qu’il n’y a plus rien à garder.","image":"L’eau placée au-dessus du feu, chacun à son rang, le chaudron enfin porté à l’ébullition. Ainsi l’homme noble, conscient que l’ordre tend vers le déclin, songe à l’infortune avant qu’elle ne vienne et s’en arme à l’avance.","lineTexts":["Il freine ses roues et trempe sa queue dans l’eau ; à se retenir au passage, il n’y a nul blâme.","La femme perd le rideau de son char ; ne cours pas après lui, car en sept jours il reviendra de lui-même.","L’Illustre Ancêtre soumet les terres du pays des démons ; après trois ans il l’emporte. Une si grande entreprise n’est pas à tenter par de moindres gens.","Même les plus beaux vêtements auront des haillons pour boucher les fuites ; sois vigilant tout le long du jour, car les coutures se relâchent déjà.","Le voisin de l’orient qui immole un bœuf n’obtient pas autant de réelle bénédiction que le voisin de l’occident avec sa modeste offrande ; la sincérité l’emporte sur la magnificence.","Il met la tête dans l’eau ; danger à l’extrême fin. S’attarder au sommet de l’accomplissement est périlleux."]},
  64: {"name":"Avant l’accomplissement","gloss":"La traversée non encore gagnée, l’ordre en formation","judgment":"Avant l’accomplissement, le succès. Mais le petit renard, presque parvenu de l’autre côté du torrent, trempe sa queue ; rien alors n’est avantageux. Quand la traversée est presque gagnée, c’est la prudence jusqu’au bout qui décide si elle l’est vraiment.","image":"Le feu au-dessus de l’eau, les deux non encore unis dans leur œuvre propre, chacun tirant de son côté. Ainsi l’homme noble prend grand soin de distinguer les choses selon leur nature, plaçant chacune à son juste rang avant que l’ordre puisse devenir entier.","lineTexts":["Il trempe sa queue dans l’eau ; pousser en avant maintenant, avant que la force soit rassemblée, apporte l’humiliation.","Il freine ses roues et se retient ; persévérer dans cette retenue apporte la fortune.","Avant l’accomplissement, se mettre en route maintenant apporte l’infortune ; pourtant il est avantageux de traverser la grande eau une fois le temps mûr.","La persévérance apporte la fortune et le remords s’évanouit. Avec une grande force on soumet le pays des démons, et après trois ans il y a des récompenses dans le grand royaume.","La persévérance apporte la fortune et nul remords. La lumière de l’homme noble est vraie, et son rayonnement apporte la fortune par la sincérité.","Avec une confiance sincère on peut boire le vin, et il n’y a nul blâme ; mais si l’on s’en trempe la tête dans un excès insouciant, même la confiance perd sa juste mesure."]},
};
